// ===== Generic CRUD =====
let _crudCfg = null;

async function renderCrud(cfg) {
  _crudCfg = cfg;
  const c = document.getElementById('content');
  c.innerHTML = `<div class="flex flex-wrap justify-between mb-4"><button id="add-btn" class="bg-[#1e40af] hover:bg-[#1d4ed8] text-white px-4 py-2 rounded-md text-sm font-medium">+ Tambah</button><button onclick="exportXlsx()" class="border border-stone-300 text-stone-700 hover:bg-stone-50 px-4 py-2 rounded-md text-sm font-medium">Export XLSX</button></div>
    <div id="table-wrap" class="bg-white border border-stone-200 rounded-lg overflow-hidden"></div>`;
  document.getElementById('add-btn').onclick = () => openForm(cfg, null);
  await reloadCrud(cfg);
}

async function reloadCrud(cfg) {
  const rows = await api.get(cfg.endpoint);
  window._crudRows = rows;
  const w = document.getElementById('table-wrap');
  if (!rows.length) { w.innerHTML = '<div class="p-12 text-center text-stone-400"><svg class="w-16 h-16 mx-auto mb-4 text-stone-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><rect x="2" y="3" width="20" height="18" rx="2" ry="2"/><path d="M12 17v-6"/><circle cx="12" cy="21" r="2"/></svg><div>Belum ada data</div><div class="text-sm mt-1 text-stone-400">Klik "Tambah" untuk mulai.</div></div>'; return; }
  const headers = cfg.cols.map(k => `<th class="text-left px-4 py-3 text-xs font-semibold text-stone-600 uppercase">${cfg.fields.find(f => f.k === k)?.l || k}</th>`).join('');
  const body = rows.map(r => `<tr class="border-t border-stone-100">
    ${cfg.cols.map(k => {
      const f = cfg.fields.find(x => x.k === k);
      const v = r[k];
      let cell = v == null || v === '' ? '-' : v;
      if (f?.fmt === 'idr') cell = `<span class="mono">${fmtIDR(v)}</span>`;
      else if (f?.fmt === 'num') cell = `<span class="mono">${fmtNum(v)}</span>`;
      else if (f?.type === 'date') cell = fmtDate(v);
      return `<td class="px-4 py-3 text-sm">${cell}</td>`;
    }).join('')}
    <td class="px-4 py-3 text-right">
      <button onclick='editRow(${JSON.stringify(cfg).replace(/'/g, "\\'")}, ${JSON.stringify(r).replace(/'/g, "\\'")})' class="text-stone-500 hover:text-stone-900 mr-2" title="Edit"><svg class="w-4 h-4 inline" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg></button>
      <button onclick='deleteRow("${cfg.endpoint}", ${r.id}, ${JSON.stringify(cfg).replace(/'/g, "\\'")})' class="text-red-600 hover:text-red-800" title="Hapus"><svg class="w-4 h-4 inline" fill="none" stroke="currentColor" viewBox="0 0 24 24"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/></svg></button>
    </td></tr>`).join('');
  w.innerHTML = `<div class="overflow-x-auto"><table class="w-full"><thead class="bg-stone-50"><tr>${headers}<th class="px-4 py-3 text-right text-xs font-semibold text-stone-600 uppercase">Aksi</th></tr></thead><tbody>${body}</tbody></table></div>`;
}

function editRow(cfg, row) { openForm(cfg, row); }
async function deleteRow(endpoint, id, cfg) {
  if (!await showConfirm('Hapus data ini?')) return;
  await api.del(endpoint + '/' + id); reloadCrud(cfg);
}

function exportXlsx() {
  const cfg = _crudCfg;
  if (!cfg) return;
  const rows = window._crudRows || [];
  if (!rows.length) { showAlert('Tidak ada data untuk diexport', 'warning'); return; }
  const headers = cfg.cols.map(k => cfg.fields.find(f => f.k === k)?.l || k);
  const data = rows.map(r => cfg.cols.map(k => r[k] == null ? '' : r[k]));
  data.unshift(headers);
  const ws = XLSX.utils.aoa_to_sheet(data);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, 'Data');
  XLSX.writeFile(wb, (cfg.title || cfg.endpoint) + '.xlsx');
}

async function exportBahanBakuXlsx() {
  const cfg = getBahanCrud();
  const rows = await api.get('/bahan_baku');
  if (!rows.length) { showAlert('Tidak ada data untuk diexport', 'warning'); return; }
  const headers = cfg.cols.map(k => cfg.fields.find(f => f.k === k)?.l || k);
  const data = rows.map(r => cfg.cols.map(k => r[k] == null ? '' : r[k]));
  data.unshift(headers);
  const ws = XLSX.utils.aoa_to_sheet(data);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, 'Bahan Baku');
  XLSX.writeFile(wb, 'bahan_baku.xlsx');
}

function renderField(f, editing) {
  if (f.type === 'hidden') {
    return `<input type="hidden" id="f-${f.k}" value="${editing?.[f.k] || ''}" />`;
  }
  const ro = f.readOnly;
  const roCls = ro ? 'bg-stone-100 text-stone-500 cursor-not-allowed' : '';
  const val = editing?.[f.k];
  let input;
  if (f.type === 'select') {
    input = `<select id="f-${f.k}" ${ro ? 'disabled' : ''} class="mt-1 w-full h-10 px-3 border border-stone-200 rounded-md text-sm ${roCls}">
      <option value="">— Pilih —</option>${f.opts.map(o => `<option value="${o}" ${val === o ? 'selected' : ''}>${o}</option>`).join('')}
    </select>`;
  } else if (f.type === 'select-api') {
    input = `<select id="f-${f.k}" ${ro ? 'disabled' : ''} class="mt-1 w-full h-10 px-3 border border-stone-200 rounded-md text-sm ${roCls}"><option value="">— Memuat data... —</option></select>`;
  } else if (f.type === 'textarea') {
    input = `<textarea id="f-${f.k}" rows="2" ${ro ? 'readonly' : ''} class="mt-1 w-full px-3 py-2 border border-stone-200 rounded-md text-sm ${roCls}">${val || ''}</textarea>`;
  } else {
    const itype = f.type === 'number' ? 'number' : f.type === 'date' ? 'date' : 'text';
    const ival = val != null ? (f.type === 'date' ? String(val).slice(0,10) : val) : '';
    input = `<input id="f-${f.k}" type="${itype}" value="${ival}" ${ro ? 'readonly' : ''} class="mt-1 w-full h-10 px-3 border border-stone-200 rounded-md text-sm ${f.type === 'number' ? 'mono' : ''} ${roCls}" />`;
  }
  return `<div class="${f.type === 'hidden' ? '' : 'mb-3'}"><label class="text-sm text-stone-700">${f.l}${f.req ? ' <span class="text-red-500">*</span>' : ''}</label>${input}</div>`;
}

function openForm(cfg, editing) {
  const title = (editing ? 'Edit ' : 'Tambah ') + MODULES[(location.pathname || '/dashboard').slice(1)].title;
  document.getElementById('modal-title').textContent = title;
  const body = document.getElementById('modal-body');

  const apiSelects = cfg.fields.filter(f => f.type === 'select-api');

  if (cfg.groups && Array.isArray(cfg.groups)) {
    let html = '';
    cfg.groups.forEach(g => {
      const gFields = cfg.fields.filter(f => f.group === g.key && f.type !== 'hidden');
      if (!gFields.length) return;
      html += `<div class="mb-6">
        <h4 class="text-sm font-semibold text-stone-700 mb-3 pb-2" style="border-bottom:1px solid var(--border)">${g.label}</h4>
        <div class="grid grid-cols-1 ${g.cols === 2 ? 'md:grid-cols-2' : ''} gap-x-4 gap-y-1">`;
      gFields.forEach(f => { html += renderField(f, editing); });
      html += `</div></div>`;
    });
    cfg.fields.filter(f => f.type === 'hidden').forEach(f => { html += renderField(f, editing); });
    body.innerHTML = html;
  } else {
    body.innerHTML = cfg.fields.map(f => renderField(f, editing)).join('');
  }

  apiSelects.forEach(f => {
    const sel = document.getElementById('f-' + f.k);
    api.get(f.source).then(rows => {
      const list = Array.isArray(rows) ? rows : (rows.data || []);
      sel.innerHTML = '<option value="">— Pilih ' + f.l + ' —</option>' +
        list.map(r => `<option value="${r[f.valueField || 'id']}" data-item='${encodeURIComponent(JSON.stringify(r))}' ${editing?.[f.k] == r[f.valueField || 'id'] ? 'selected' : ''}>${r[f.labelField || 'nama']}</option>`).join('');
      sel.onchange = function() {
        const opt = sel.options[sel.selectedIndex];
        if (opt && opt.dataset.item) {
          const item = JSON.parse(decodeURIComponent(opt.dataset.item));
          if (f.fill) Object.keys(f.fill).forEach(key => {
            const src = document.getElementById('f-' + key);
            if (src) src.value = item[f.fill[key]] || '';
          });
          if (f.fillApi && item[f.fillApi.param]) {
            api.get(f.fillApi.url + '?kategori=' + encodeURIComponent(item[f.fillApi.param])).then(r => {
              const tgt = document.getElementById('f-' + f.fillApi.target);
              if (tgt && r.total) tgt.value = r.total;
            });
          }
        }
      };
    });
  });

  document.getElementById('modal-save').onclick = async () => {
    var rules = cfg.fields.filter(function(f) { return f.req; }).map(function(f) {
      return { id: 'f-' + f.k, label: f.l, type: (f.type === 'select' || f.type === 'select-api') ? 'select' : (f.type === 'number' ? 'number' : 'text') };
    });
    if (!validateForm(rules)) return;
    const payload = {};
    cfg.fields.forEach(f => { const v = document.getElementById('f-' + f.k).value; payload[f.k] = f.type === 'number' ? Number(v) || 0 : v; });
    if (editing) await api.put(cfg.endpoint + '/' + editing.id, payload);
    else await api.post(cfg.endpoint, payload);
    closeModal(); reloadCrud(cfg);
  };
  document.getElementById('modal').classList.remove('hidden');
  document.getElementById('modal').classList.add('flex');
}
function showConfirm(msg) {
  return new Promise((resolve) => {
    const modal = document.getElementById('confirm-modal');
    document.getElementById('confirm-message').textContent = msg;
    document.getElementById('confirm-ok').onclick = () => {
      modal.classList.add('hidden');
      modal.classList.remove('flex');
      resolve(true);
    };
    document.getElementById('confirm-cancel').onclick = () => {
      modal.classList.add('hidden');
      modal.classList.remove('flex');
      resolve(false);
    };
    modal.classList.remove('hidden');
    modal.classList.add('flex');
  });
}

function showAlert(msg, type) {
  var modal = document.getElementById('alert-modal');
  if (!modal) return;
  var titleEl = document.getElementById('alert-title');
  var msgEl = document.getElementById('alert-message');
  var iconWrap = document.getElementById('alert-icon');
  var svgEl = document.getElementById('alert-svg');
  var okBtn = document.getElementById('alert-ok');
  var colors = {
    warning: { bg: 'bg-amber-100', text: 'text-amber-600', btn: 'bg-amber-600 hover:bg-amber-700', icon: 'M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z', title: 'Perhatian' },
    error: { bg: 'bg-red-100', text: 'text-red-600', btn: 'bg-red-600 hover:bg-red-700', icon: 'M10 14l2-2m0 0l2-2m-2 2l-2-2m2 2l2 2m7-2a9 9 0 11-18 0 9 9 0 0118 0z', title: 'Error' },
    success: { bg: 'bg-emerald-100', text: 'text-emerald-600', btn: 'bg-emerald-600 hover:bg-emerald-700', icon: 'M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z', title: 'Berhasil' },
  };
  var isDark = document.documentElement.classList.contains('dark');
  var c = colors[type] || colors.warning;
  if (isDark) {
    var darkMap = { 'bg-amber-100': 'bg-[#451a03]', 'bg-red-100': 'bg-[#450a0a]', 'bg-emerald-100': 'bg-[#064e3b]' };
    var textDarkMap = { 'text-amber-600': 'text-amber-300', 'text-red-600': 'text-red-300', 'text-emerald-600': 'text-emerald-300' };
    iconWrap.className = 'w-10 h-10 rounded-full ' + (darkMap[c.bg] || c.bg) + ' flex items-center justify-center shrink-0';
    svgEl.className = 'w-5 h-5 ' + (textDarkMap[c.text] || c.text);
  } else {
    iconWrap.className = 'w-10 h-10 rounded-full ' + c.bg + ' flex items-center justify-center shrink-0';
    svgEl.className = 'w-5 h-5 ' + c.text;
  }
  (svgEl.querySelector('path') || svgEl).setAttribute('d', c.icon);
  titleEl.textContent = c.title;
  msgEl.textContent = msg;
  okBtn.className = 'px-5 py-2 text-sm font-medium text-white rounded-lg transition-colors ' + c.btn;
  okBtn.onclick = function() {
    modal.classList.add('hidden');
    modal.classList.remove('flex');
  };
  modal.classList.remove('hidden');
  modal.classList.add('flex');
}

function validateForm(rules) {
  for (var i = 0; i < rules.length; i++) {
    var r = rules[i];
    var el = document.getElementById(r.id);
    if (!el) continue;
    var val = el.value;
    if (r.type === 'select' && !val) {
      showAlert(r.label + ' harus dipilih', 'warning');
      el.focus();
      el.scrollIntoView({ behavior: 'smooth', block: 'center' });
      return false;
    }
    if (r.type === 'number') {
      if (val === '' || Number(val) === 0) {
        showAlert(r.label + ' harus diisi', 'warning');
        el.focus();
        el.scrollIntoView({ behavior: 'smooth', block: 'center' });
        return false;
      }
      continue;
    }
    if (!val || !val.trim()) {
      showAlert(r.label + ' harus diisi', 'warning');
      el.focus();
      el.scrollIntoView({ behavior: 'smooth', block: 'center' });
      return false;
    }
  }
  return true;
}

function showToast(msg, type) {
  var c = document.getElementById('toast-container');
  if (!c) return;
  var colors = { success: 'bg-emerald-600', error: 'bg-red-600', warning: 'bg-amber-500' };
  var el = document.createElement('div');
  el.className = (colors[type] || 'bg-stone-800') + ' text-white px-4 py-2.5 rounded-lg text-sm shadow-lg pointer-events-auto animate-alert-in';
  el.textContent = msg;
  c.appendChild(el);
  setTimeout(function() {
    el.style.opacity = '0';
    el.style.transition = 'opacity 0.3s';
    setTimeout(function() { el.remove(); }, 300);
  }, 3000);
}

function closeModal(id) {
  // Restore modal footer if hidden by wizard
  var saveBtn = document.getElementById('modal-save');
  if (saveBtn) saveBtn.style.display = '';
  var footer = document.querySelector('#modal > div > div.border-t.flex.justify-end:last-child');
  if (footer) footer.style.display = '';
  
  var m = document.getElementById(id || 'modal');
  if (m) { m.classList.add('hidden'); m.classList.remove('flex'); }
}
async function renderDashboard() {
  const c = document.getElementById('content');
  c.innerHTML = '<div class="flex items-center justify-center py-24"><svg class="animate-spin h-10 w-10 text-[#1e40af]" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"/><path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"/></svg></div>';
  try {
    const r = await fetch('/api/template/dashboard', { credentials: 'include' });
    if (!r.ok) {
      const err = await r.json();
      throw new Error(err.error || 'Gagal memuat dashboard');
    }
    c.innerHTML = await r.text();
  } catch (err) {
    console.error('Dashboard error:', err);
    c.innerHTML = `<div class="bg-red-50 border border-red-200 text-red-700 p-4 rounded-lg">Gagal memuat dashboard: ${err.message}</div>`;
  }
}
// ===== Menu (custom with bahan) =====
let menuState = { page: 1, limit: 10, search: '', total: 0, totalPages: 1 };

async function renderMenu() {
  const c = document.getElementById('content');
  if (!c) return;
  c.innerHTML = '<div class="flex items-center justify-center py-24"><svg class="animate-spin h-10 w-10 text-[#1e40af]" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"/><path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"/></svg></div>';
  try {
    const params = new URLSearchParams({ page: menuState.page, limit: menuState.limit, search: menuState.search });
    const r = await fetch('/api/menu?' + params, { credentials: 'include' });
    if (!r.ok) {
      const err = await r.json().catch(() => ({}));
      throw new Error(err.error || 'Gagal memuat menu');
    }
    const data = await r.json();
    const pagination = data.pagination || { total: data.length || 0, totalPages: 1, page: menuState.page };
    menuState = { ...menuState, total: pagination.total, totalPages: pagination.totalPages, page: pagination.page };
    
    const bahan = await api.get('/bahan_baku');
    window._bahanBaku = bahan;
    
    c.innerHTML = renderMenuHtml(Array.isArray(data.data) ? data.data : (Array.isArray(data) ? data : []));
    renderPagination();
    attachMenuHandlers();
  } catch (err) {
    console.error('Menu error:', err);
    c.innerHTML = `<div class="bg-red-50 border border-red-200 text-red-700 p-4 rounded-lg">Gagal memuat menu: ${err.message}</div>`;
  }
}

const KATEGORI_COLORS = {
  'Ibu Hamil': { bg: '#be123c' },
  'Ibu Menyusui': { bg: '#6d28d9' },
  'Balita': { bg: '#0e7490' },
  'PAUD': { bg: '#047857' },
  'TK': { bg: '#b45309' },
  'SD': { bg: '#c2410c' },
  'SMP': { bg: '#1d4ed8' },
};

function kategoriBadge(kat) {
  const c = KATEGORI_COLORS[kat] || { bg: '#78716c' };
  return `<span class="inline-block px-2.5 py-0.5 rounded-full text-xs font-medium text-white" style="background:${c.bg};">${kat}</span>`;
}

function renderMenuHtml(menus) {
  return `<div class="flex flex-wrap justify-between gap-2 mb-4">
    <button id="add-menu-btn" class="bg-[#1e40af] hover:bg-[#1d4ed8] text-white px-4 py-2 rounded-md text-sm font-medium">+ Tambah Menu</button>
    <div class="relative">
      <input type="text" id="search-menu-input" placeholder="Cari nama menu..." value="${menuState.search}"
        class="pl-10 pr-4 py-2 border border-stone-200 rounded-md text-sm w-48 focus:outline-none focus:border-[#1e40af]">
      <svg class="absolute left-3 top-2.5 w-4 h-4 text-stone-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
        <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path>
      </svg>
    </div>
  </div>
  <div class="bg-white border border-stone-200 rounded-lg overflow-hidden">
    <div class="overflow-x-auto">
      <table class="w-full">
        <thead class="bg-stone-50">
          <tr>
            <th class="text-left px-4 py-3 text-xs font-semibold uppercase">Nama</th>
            <th class="text-left px-4 py-3 text-xs font-semibold uppercase">Kategori</th>
            <th class="text-right px-4 py-3 text-xs font-semibold uppercase">Gramasi</th>
            <th class="text-right px-4 py-3 text-xs font-semibold uppercase">Kalori</th>
            <th class="text-right px-4 py-3 text-xs font-semibold uppercase">Bahan</th>
            <th class="text-right px-4 py-3 text-xs font-semibold uppercase">Aksi</th>
          </tr>
        </thead>
        <tbody id="menu-table-body">
          ${menus.length > 0 ? menus.map(m => `
            <tr class="border-t border-stone-100">
              <td class="px-4 py-3 text-sm font-medium truncate max-w-[180px]" title="${m.nama}">${m.nama}</td>
              <td class="px-4 py-3 text-sm whitespace-nowrap">${m.kategori_penerima ? kategoriBadge(m.kategori_penerima) : '-'}</td>
              <td class="px-4 py-3 text-sm text-right mono whitespace-nowrap">${m.gramasi_total}g</td>
              <td class="px-4 py-3 text-sm text-right mono whitespace-nowrap">${m.kalori} kkal</td>
              <td class="px-4 py-3 text-sm text-right mono whitespace-nowrap">${(m.bahan && m.bahan.length) || 0}</td>
              <td class="px-4 py-3 text-sm text-right whitespace-nowrap">
                <button data-menu-id="${m.id}" class="edit-btn text-stone-500 hover:text-stone-900 mr-2" title="Edit"><svg class="w-4 h-4 inline" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg></button>
                <button data-menu-id="${m.id}" class="delete-btn text-red-600 hover:text-red-800" title="Hapus"><svg class="w-4 h-4 inline" fill="none" stroke="currentColor" viewBox="0 0 24 24"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/></svg></button>
              </td>
            </tr>`).join('') : '<tr><td colspan="6" class="text-center py-12 text-stone-400"><svg class="w-14 h-14 mx-auto mb-3 text-stone-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M3 2v7c0 1.1.9 2 2 2h4a2 2 0 0 0 2-2V2"/><path d="M7 2v20"/><path d="M21 15V2v0a5 5 0 0 0-5 5v6c0 1.1.9 2 2 2h3Zm0 0v7"/></svg><div>Belum ada menu</div></td></tr>'}
        </tbody>
      </table>
    </div>
  </div>
  <div id="pagination-controls"></div>`;
}

function renderPagination() {
  const wrap = document.getElementById('pagination-controls');
  if (!wrap) return;
  if (menuState.totalPages <= 1) { wrap.innerHTML = ''; return; }
  wrap.innerHTML = `<div class="flex items-center justify-start gap-2 mt-4">
    ${menuState.page > 1 ? '<button onclick="goToPage(' + (menuState.page - 1) + ')" class="px-4 py-1.5 text-sm rounded border border-stone-200 hover:bg-stone-50">Prev</button>' : ''}
    <span class="text-sm text-stone-500">Halaman ${menuState.page} dari ${menuState.totalPages}</span>
    ${menuState.page < menuState.totalPages ? '<button onclick="goToPage(' + (menuState.page + 1) + ')" class="px-4 py-1.5 text-sm rounded border border-stone-200 hover:bg-stone-50">Next</button>' : ''}
  </div>`;
}

function goToPage(page) {
  menuState.page = page;
  renderMenu();
}

function attachMenuHandlers() {
  const addBtn = document.getElementById('add-menu-btn');
  if (addBtn) addBtn.onclick = () => openMenuForm(null);
  const searchInput = document.getElementById('search-menu-input');
  if (searchInput) {
    let timer;
    searchInput.oninput = function() {
      clearTimeout(timer);
      timer = setTimeout(() => {
        menuState.search = this.value;
        menuState.page = 1;
        renderMenu();
      }, 300);
    };
  }
  document.querySelectorAll('.edit-btn').forEach(btn => {
    btn.addEventListener('click', function() {
      const menuId = this.getAttribute('data-menu-id');
      fetch('/api/menu/' + menuId)
        .then(r => r.json())
        .then(menu => openMenuForm(menu));
    });
  });
  document.querySelectorAll('.delete-btn').forEach(btn => {
    btn.addEventListener('click', function() {
      const menuId = this.getAttribute('data-menu-id');
      deleteMenu(menuId);
    });
  });
}

function openMenuForm(editing) {
  const m = editing || { nama: '', kategori_penerima: '', deskripsi: '', gramasi_total: 0, kalori: 0, protein: 0, karbohidrat: 0, lemak: 0, serat: 0, bahan: [] };
  document.getElementById('modal-title').textContent = editing ? 'Edit Menu' : 'Tambah Menu';
  document.getElementById('modal-body').innerHTML = `
    <div class="grid grid-cols-2 gap-3">
      <div><label class="text-sm">Nama Menu *</label><input id="m-nama" value="${m.nama}" class="mt-1 w-full h-10 px-3 border border-stone-200 rounded-md" /></div>
      <div><label class="text-sm">Kategori Penerima</label>
        <select id="m-kategori" class="mt-1 w-full h-10 px-3 border border-stone-200 rounded-md">
          <option value="">—</option>${['Ibu Hamil','Ibu Menyusui','Balita','PAUD','TK','SD','SMP'].map(o => `<option value="${o}" ${m.kategori_penerima === o ? 'selected':''}>${o}</option>`).join('')}
        </select></div>
    </div>
    <div class="mt-3"><label class="text-sm">Deskripsi</label><textarea id="m-deskripsi" rows="2" class="mt-1 w-full px-3 py-2 border border-stone-200 rounded-md">${m.deskripsi || ''}</textarea></div>
    <div class="grid grid-cols-5 gap-2 mt-3">
      ${[['gramasi_total','Gramasi'],['kalori','Kalori'],['protein','Protein'],['karbohidrat','Karbo'],['lemak','Lemak']].map(([k,l]) =>
        `<div><label class="text-xs">${l}</label><input id="m-${k}" type="number" value="${m[k] || 0}" class="mt-1 w-full h-9 px-2 border border-stone-200 rounded-md mono text-sm" /></div>`).join('')}
    </div>
    <div class="border-t border-stone-200 mt-4 pt-3">
      <div class="flex justify-between items-center mb-2">
        <div class="font-semibold text-sm">Bahan & Gramasi</div>
        <button type="button" onclick="addBahanRow()" class="text-xs border border-stone-300 px-3 py-1 rounded">+ Tambah Bahan</button>
      </div>
      <div id="bahan-list" class="space-y-2"></div>
    </div>`;
  window._menuBahan = (m.bahan || []).map(b => ({ bahan_baku_id: b.bahan_baku_id, jumlah: b.jumlah }));
  renderBahanList();
  document.getElementById('modal-save').onclick = async () => {
    if (!validateForm([{ id: 'm-nama', label: 'Nama Menu' }])) return;
    const payload = {
      nama: document.getElementById('m-nama').value,
      kategori_penerima: document.getElementById('m-kategori').value,
      deskripsi: document.getElementById('m-deskripsi').value,
      gramasi_total: +document.getElementById('m-gramasi_total').value || 0,
      kalori: +document.getElementById('m-kalori').value || 0,
      protein: +document.getElementById('m-protein').value || 0,
      karbohidrat: +document.getElementById('m-karbohidrat').value || 0,
      lemak: +document.getElementById('m-lemak').value || 0,
      bahan: window._menuBahan.filter(b => b.bahan_baku_id && (b.jumlah || b.kategori_sp)),
    };
    if (editing) await api.put('/menu/' + editing.id, payload);
    else await api.post('/menu', payload);
    closeModal(); renderMenu();
  };
  document.getElementById('modal').classList.remove('hidden');
  document.getElementById('modal').classList.add('flex');
}
function addBahanRow() { window._menuBahan.push({ bahan_baku_id: '', jumlah: 0, satuan: '' }); renderBahanList(); }
function removeBahanRow(i) { window._menuBahan.splice(i, 1); renderBahanList(); }
function updateBahan(i, k, v) {
  window._menuBahan[i][k] = k === 'jumlah' ? +v : v;
  if (k === 'bahan_baku_id') {
    const bb = (window._bahanBaku || []).find(b => b.id == v);
    window._menuBahan[i].satuan = bb ? bb.satuan : '';
    window._menuBahan[i].kategori_sp = bb ? bb.kategori_sp : '';
    window._menuBahan[i].berat_1_sp = bb ? (+bb.berat_1_sp || 0) : 0;
    window._menuBahan[i].persen_bdd = bb ? (+bb.persen_bdd || 100) : 100;
    // Auto-calculate jumlah from SP if menu has kategori_penerima and bahan has SP data
    if (bb && bb.kategori_sp && bb.berat_1_sp > 0) {
      var katPenerima = document.getElementById('m-kategori')?.value;
      if (katPenerima) {
        window._menuBahan[i].jumlah = +bb.berat_1_sp;
        // We'll set a placeholder; the actual SP value will be calculated on the server
      }
    }
    renderBahanList();
  }
}
function renderBahanList() {
  var mKat = document.getElementById('m-kategori')?.value || '';
  document.getElementById('bahan-list').innerHTML = window._menuBahan.map((b, i) => {
    var bb = (window._bahanBaku || []).find(x => x.id == b.bahan_baku_id);
    var spInfo = '';
    if (bb && bb.kategori_sp && bb.berat_1_sp > 0) {
      spInfo = '<div class="col-span-2 text-[10px] text-stone-400 leading-tight">' + bb.kategori_sp + ' · 1SP=' + bb.berat_1_sp + 'g · BDD=' + bb.persen_bdd + '%</div>';
      if (!b.jumlah && bb.berat_1_sp > 0) {
        window._menuBahan[i].jumlah = +bb.berat_1_sp;
      }
    }
    return '<div class="grid grid-cols-12 gap-1.5 items-center">' +
      '<select onchange="updateBahan(' + i + ', \'bahan_baku_id\', this.value)" class="col-span-5 h-9 px-2 border border-stone-200 rounded-md text-sm">' +
        '<option value="">— Pilih —</option>' +
        window._bahanBaku.map(function(x) { return '<option value="' + x.id + '" ' + (b.bahan_baku_id == x.id ? 'selected' : '') + '>' + x.nama + '</option>'; }).join('') +
      '</select>' +
      '<input type="text" value="' + (b.satuan || '') + '" readonly class="col-span-1 h-9 px-2 border border-stone-200 rounded-md text-sm bg-stone-50 text-stone-500" placeholder="unit" />' +
      '<input type="number" value="' + (b.jumlah || '') + '" onchange="updateBahan(' + i + ', \'jumlah\', this.value)" placeholder="gram" class="col-span-3 h-9 px-2 border border-stone-200 rounded-md text-sm mono" />' +
      (spInfo || '<div class="col-span-2"></div>') +
      '<button type="button" onclick="removeBahanRow(' + i + ')" class="col-span-1 text-red-600 text-center py-2">×</button>' +
    '</div>';
  }).join('');
}
async function deleteMenu(id) { if (!await showConfirm('Hapus menu?')) return; await api.del('/menu/' + id); renderMenu(); }

function openAIDialog() {
  document.getElementById('modal-title').textContent = '✨ Saran Menu AI';
  document.getElementById('modal-body').innerHTML = `
    <div><label class="text-sm">Kategori Penerima</label>
      <select id="ai-kat" class="mt-1 w-full h-10 px-3 border border-stone-200 rounded-md">
        ${['Ibu Hamil','Ibu Menyusui','Balita','PAUD','TK','SD','SMP'].map(o => `<option>${o}</option>`).join('')}
      </select></div>
    <div class="mt-3"><label class="text-sm">Catatan (opsional)</label>
      <textarea id="ai-note" rows="2" class="mt-1 w-full px-3 py-2 border border-stone-200 rounded-md" placeholder="Mis. hindari kacang, bahan lokal Jawa Tengah"></textarea></div>
    <button onclick="runAI()" class="mt-3 bg-orange-600 hover:bg-orange-700 text-white px-4 py-2 rounded-md text-sm font-medium">Buat Saran</button>
    <div id="ai-out" class="mt-4"></div>`;
  document.getElementById('modal-save').style.display = 'none';
  document.getElementById('modal').classList.remove('hidden');
  document.getElementById('modal').classList.add('flex');
}
async function runAI() {
  document.getElementById('ai-out').innerHTML = '<div class="text-stone-500 text-sm">⏳ Membuat saran...</div>';
  const r = await fetch('/api/ai/suggest-menu', { method:'POST', headers:{'Content-Type':'application/json'},
    body: JSON.stringify({ kategori: document.getElementById('ai-kat').value, catatan: document.getElementById('ai-note').value }) });
  const data = await r.json();
  if (!r.ok) { document.getElementById('ai-out').innerHTML = `<div class="text-red-700 text-sm">${data.error}</div>`; return; }
  const s = data.suggestion;
  document.getElementById('ai-out').innerHTML = `
    <div class="bg-orange-50 border border-orange-200 rounded p-3">
      <div class="font-bold">${s.nama_menu}</div>
      <div class="text-sm text-stone-700 mt-1">${s.deskripsi || ''}</div>
      ${s.kandungan_gizi ? `<div class="grid grid-cols-5 gap-2 my-2 text-xs">${Object.entries(s.kandungan_gizi).map(([k,v]) => `<div class="bg-white p-2 rounded"><div class="text-stone-500 uppercase">${k}</div><div class="mono">${v}</div></div>`).join('')}</div>` : ''}
      ${s.bahan ? `<div class="text-xs mt-2"><div class="font-semibold mb-1">Bahan:</div><ul class="space-y-0.5">${s.bahan.map(b => `<li>• ${b.nama} — <span class="mono">${b.jumlah} ${b.satuan}</span></li>`).join('')}</ul></div>` : ''}
    </div>`;
}

// ===== Bahan Baku (custom with sync, search, pagination & nutrisi) =====
const BAHAN_BAKU_CRUD_BASE = {
  endpoint: '/bahan_baku',
  groups: [
    { key: 'info', label: 'Informasi Dasar', cols: 2 },
    { key: 'harga_stok', label: 'Harga & Stok', cols: 2 },
    { key: 'nutrisi', label: 'Informasi Nutrisi', cols: 2 },
  ],
  fields: [
    { k: 'kode', l: 'Kode SKU', group: 'info' },
    { k: 'nama', l: 'Nama Bahan', req: true, group: 'info' },
    { k: 'kategori', l: 'Kategori', type: 'select', opts: ['Karbohidrat','Protein Hewani','Protein Nabati','Sayur','Buah','Bumbu','Lainnya'], group: 'info' },
    { k: 'satuan', l: 'Satuan (kg/gr/liter)', req: true, group: 'info' },
    { k: 'harga_satuan', l: 'Harga Satuan (IDR)', type: 'number', fmt: 'idr', group: 'harga_stok' },
    { k: 'stok_saat_ini', l: 'Stok Saat Ini', type: 'number', fmt: 'num', group: 'harga_stok' },
    { k: 'stok_minimum', l: 'Stok Minimum', type: 'number', fmt: 'num', group: 'harga_stok' },
    { k: 'kalori', l: 'Kalori (kkal)', type: 'number', fmt: 'num', group: 'nutrisi' },
    { k: 'protein', l: 'Protein (g)', type: 'number', fmt: 'num', group: 'nutrisi' },
    { k: 'karbohidrat', l: 'Karbohidrat (g)', type: 'number', fmt: 'num', group: 'nutrisi' },
    { k: 'lemak', l: 'Lemak (g)', type: 'number', fmt: 'num', group: 'nutrisi' },
    { k: 'serat', l: 'Serat (g)', type: 'number', fmt: 'num', group: 'nutrisi' },
    { k: 'kategori_sp', l: 'Kategori SP', type: 'select', opts: ['','Karbohidrat','Protein Hewani','Protein Nabati','Sayur','Buah','Susu','Minyak'], group: 'info' },
    { k: 'berat_1_sp', l: 'Berat 1 SP (gram)', type: 'number', fmt: 'num', group: 'info' },
    { k: 'persen_bdd', l: 'BDD (%)', type: 'number', fmt: 'num', group: 'info' },
  ],
  cols: ['nama','kategori','kategori_sp','berat_1_sp','persen_bdd','satuan','harga_satuan','stok_saat_ini']
};

const NUTRISI_FIELDS = ['kalori','protein','karbohidrat','lemak','serat'];

function getBahanCrud() {
  if (currentUser?.role === 'ahli_gizi') {
    return {
      ...BAHAN_BAKU_CRUD_BASE,
      fields: BAHAN_BAKU_CRUD_BASE.fields.map(f => ({
        ...f,
        readOnly: !NUTRISI_FIELDS.includes(f.k),
      })),
      cols: BAHAN_BAKU_CRUD_BASE.cols,
    };
  }
  return BAHAN_BAKU_CRUD_BASE;
}

let bahanBakuState = { page: 1, limit: 10, search: '', total: 0, totalPages: 1 };
let bahanSyncInterval = null;
const BAHAN_SYNC_INTERVAL_MS = 3 * 60 * 60 * 1000; // 3 jam

async function renderBahanBaku() {
  if (bahanSyncInterval) { clearInterval(bahanSyncInterval); bahanSyncInterval = null; }

  const c = document.getElementById('content');
  c.innerHTML = '<div class="flex items-center justify-center py-24"><svg class="animate-spin h-10 w-10 text-[#1e40af]" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"/><path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"/></svg></div>';
  try {
    const r = await fetch('/api/template/bahan-baku', { credentials: 'include' });
    c.innerHTML = await r.text();
  } catch (e) {
    c.innerHTML = `<div class="bg-red-50 border border-red-200 text-red-700 p-4 rounded-lg">Gagal memuat halaman: ${e.message}</div>`;
    return;
  }

  const isAhliGizi = currentUser?.role === 'ahli_gizi';

  document.getElementById('add-btn').style.display = isAhliGizi ? 'none' : '';
  document.getElementById('add-btn').onclick = () => openForm(getBahanCrud(), null);

  const searchInput = document.getElementById('bahan-search');
  let debounceTimer;
  searchInput.oninput = function() {
    clearTimeout(debounceTimer);
    debounceTimer = setTimeout(() => {
      bahanBakuState.search = this.value;
      bahanBakuState.page = 1;
      loadBahanBaku();
    }, 300);
  };

  await loadBahanBaku();

  showToast('Daftar bahan baku sedang diperbarui...', 'success');
  syncBahanBaku();
  bahanSyncInterval = setInterval(syncBahanBaku, BAHAN_SYNC_INTERVAL_MS);
}

async function loadBahanBaku() {
  const params = new URLSearchParams({ page: bahanBakuState.page, limit: bahanBakuState.limit, search: bahanBakuState.search });
  const res = await api.get('/bahan_baku?' + params);
  const data = Array.isArray(res.data) ? res.data : (Array.isArray(res) ? res : []);
  const pagination = res.pagination || { total: data.length, totalPages: 1, page: 1 };
  bahanBakuState = { ...bahanBakuState, total: pagination.total, totalPages: pagination.totalPages, page: pagination.page };

  renderBahanBakuTable(data);
  renderBahanPagination();
}

function renderBahanBakuTable(rows) {
  const w = document.getElementById('table-wrap');
  if (!rows.length) {
    w.innerHTML = '<div class="p-12 text-center text-stone-400"><svg class="w-16 h-16 mx-auto mb-4 text-stone-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><rect x="2" y="3" width="20" height="18" rx="2" ry="2"/><path d="M12 17v-6"/><circle cx="12" cy="21" r="2"/></svg><div>Belum ada data</div><div class="text-sm mt-1 text-stone-400">Klik "Tambah" untuk mulai.</div></div>';
    return;
  }
  const fields = getBahanCrud();
  const headers = fields.cols.map(k => `<th class="text-left px-4 py-3 text-xs font-semibold text-stone-600 uppercase">${fields.fields.find(f => f.k === k)?.l || k}</th>`).join('');
  const body = rows.map(r => `<tr class="border-t border-stone-100">
    ${fields.cols.map(k => {
      const f = fields.fields.find(x => x.k === k);
      const v = r[k];
      let cell = v == null || v === '' ? '-' : v;
      if (f?.fmt === 'idr') {
        cell = `<span class="mono">${fmtIDR(v)}</span>`;
        if (k === 'harga_satuan' && r.harga_sebelumnya > 0) {
          const prev = Number(r.harga_sebelumnya);
          const curr = Number(v);
          if (curr > prev) cell += ` <span class="text-green-600 text-xs">▲</span>`;
          else if (curr < prev) cell += ` <span class="text-red-600 text-xs">▼</span>`;
          else cell += ` <span class="text-stone-400 text-xs">—</span>`;
        }
      }
      else if (f?.fmt === 'num') cell = `<span class="mono">${fmtNum(v)}</span>`;
      else if (f?.type === 'date') cell = fmtDate(v);
      return `<td class="px-4 py-3 text-sm">${cell}</td>`;
    }).join('')}
    <td class="px-4 py-3 text-right">
      <button onclick='editBahanBaku(${JSON.stringify(r).replace(/'/g, "\\'")})' class="text-stone-500 hover:text-stone-900 mr-2" title="Edit"><svg class="w-4 h-4 inline" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg></button>
      ${currentUser?.role !== 'ahli_gizi' ? `<button onclick='deleteBahanBaku(${r.id})' class="text-red-600 hover:text-red-800" title="Hapus"><svg class="w-4 h-4 inline" fill="none" stroke="currentColor" viewBox="0 0 24 24"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/></svg></button>` : ''}
    </td></tr>`).join('');
  w.innerHTML = `<div class="overflow-x-auto"><table class="w-full"><thead class="bg-stone-50"><tr>${headers}<th class="px-4 py-3 text-right text-xs font-semibold text-stone-600 uppercase">Aksi</th></tr></thead><tbody>${body}</tbody></table></div>`;
}

function editBahanBaku(row) { openForm(getBahanCrud(), row); }
async function deleteBahanBaku(id) {
  const ok = await showConfirm('Hapus data ini?');
  if (!ok) return;
  await api.del('/bahan_baku/' + id);
  loadBahanBaku();
}

function renderBahanPagination() {
  const wrap = document.getElementById('bahan-pagination');
  if (!wrap) return;
  if (bahanBakuState.totalPages <= 1) { wrap.innerHTML = ''; return; }

  const prevBtn = bahanBakuState.page > 1 ? `<button onclick="bahanGoToPage(${bahanBakuState.page - 1})" class="px-2 py-1 text-sm rounded border border-stone-200 hover:bg-stone-50">Prev</button>` : '';
  const nextBtn = bahanBakuState.page < bahanBakuState.totalPages ? `<button onclick="bahanGoToPage(${bahanBakuState.page + 1})" class="px-2 py-1 text-sm rounded border border-stone-200 hover:bg-stone-50">Next</button>` : '';
  wrap.innerHTML = `<span class="text-sm text-stone-500">Hal ${bahanBakuState.page} dari ${bahanBakuState.totalPages}</span>
    <div class="flex gap-2">${prevBtn}${nextBtn}</div>`;
}

function bahanGoToPage(page) {
  bahanBakuState.page = page;
  loadBahanBaku();
}

async function syncBahanBaku() {
  try {
    const result = await api.post('/bahan-baku/sync', {});
    showToast(`Bahan baku diperbarui: ${result.imported} baru, ${result.updated} berubah dari ${result.total} data`, 'success');
    bahanBakuState.page = 1;
    await loadBahanBaku();
  } catch (e) {
    console.log('Auto-sync bahan baku:', e.message);
  }
}

// ===== Gudang (with search & pagination) =====
window.addEventListener('unhandledrejection', e => {
  console.error('[UNHANDLED]', e.reason);
});

let gudangState = { tab: 'stok', page: 1, limit: 10, search: '', total: 0, totalPages: 1 };

async function renderGudang() {
  const c = document.getElementById('content');
  c.innerHTML = '<div class="flex items-center justify-center py-24"><svg class="animate-spin h-10 w-10 text-[#1e40af]" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"/><path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"/></svg></div>';
  try {
    const r = await fetch('/api/template/gudang', { credentials: 'include' });
    if (!r.ok) {
      const err = await r.json();
      throw new Error(err.error || 'Gagal memuat gudang');
    }
    c.innerHTML = await r.text();

    // Search
    const searchInput = document.getElementById('gudang-search');
    let debounceTimer;
    searchInput.oninput = function() {
      clearTimeout(debounceTimer);
      debounceTimer = setTimeout(() => {
        gudangState.search = this.value;
        gudangState.page = 1;
        loadGudang();
      }, 300);
    };

    // Load initial
    gudangState.tab = 'stok';
    await loadGudang();
  } catch (err) {
    c.innerHTML = `<div class="bg-red-50 border border-red-200 text-red-700 p-4 rounded-lg">Gagal memuat gudang: ${err.message}</div>`;
  }
}

function showGudang(tab) {
  gudangState.tab = tab;
  gudangState.page = 1;
  gudangState.search = '';
  const searchInput = document.getElementById('gudang-search');
  if (searchInput) searchInput.value = '';
  const tabColors = {
    stok: { active: 'bg-white text-blue-600 shadow-sm', inactive: 'bg-blue-100 text-blue-700 hover:bg-blue-200' },
    masuk: { active: 'bg-white text-emerald-600 shadow-sm', inactive: 'bg-emerald-100 text-emerald-700 hover:bg-emerald-200' },
    keluar: { active: 'bg-white text-orange-600 shadow-sm', inactive: 'bg-orange-100 text-orange-700 hover:bg-orange-200' },
  };
  ['stok','masuk','keluar'].forEach(t => {
    const el = document.getElementById('tab-'+t);
    const c = tabColors[t];
    const base = 'px-3 sm:px-5 py-2 sm:py-2.5 text-xs sm:text-sm font-medium rounded-t-lg border border-b-0 border-stone-200 -mb-px';
    const extra = t === tab ? ' relative z-[2]' : '';
    if (el) el.className = base + ' ' + (t === tab ? c.active : c.inactive) + extra;
  });
  loadGudang();
}

async function loadGudang() {
  const wrap = document.getElementById('gudang-content');
  const pagWrap = document.getElementById('gudang-pagination');
  if (!wrap) return;
  wrap.innerHTML = '<div class="flex items-center justify-center py-16"><svg class="animate-spin h-8 w-8 text-[#1e40af]" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"/><path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"/></svg></div>';

  try {
    const params = new URLSearchParams({ page: gudangState.page, limit: gudangState.limit, search: gudangState.search });

    if (gudangState.tab === 'stok') {
      const res = await api.get('/bahan_baku?' + params);
      const data = Array.isArray(res.data) ? res.data : (Array.isArray(res) ? res : []);
      const pagination = res.pagination || { total: data.length, totalPages: 1, page: 1 };
      gudangState = { ...gudangState, total: pagination.total, totalPages: pagination.totalPages, page: pagination.page };

      wrap.innerHTML = `<div class="bg-white border border-stone-200 rounded-lg overflow-hidden"><div class="overflow-x-auto"><table class="w-full">
        <thead class="bg-stone-50"><tr>
          <th class="text-left px-4 py-3 text-xs font-semibold uppercase whitespace-nowrap">Nama</th>
          <th class="text-left px-4 py-3 text-xs font-semibold uppercase whitespace-nowrap">Kategori</th>
          <th class="text-right px-4 py-3 text-xs font-semibold uppercase whitespace-nowrap">Stok</th>
          <th class="text-left px-4 py-3 text-xs font-semibold uppercase whitespace-nowrap">Satuan</th>
          <th class="text-right px-4 py-3 text-xs font-semibold uppercase whitespace-nowrap">Min</th>
          <th class="text-left px-4 py-3 text-xs font-semibold uppercase whitespace-nowrap">Status</th>
        </tr></thead><tbody>
        ${data.map(b => {
          const low = Number(b.stok_saat_ini) < Number(b.stok_minimum);
          return `<tr class="border-t border-stone-100">
            <td class="px-4 py-3 text-sm font-medium whitespace-nowrap">${b.nama}</td>
            <td class="px-4 py-3 text-sm whitespace-nowrap">${b.kategori || '-'}</td>
            <td class="px-4 py-3 text-sm text-right mono whitespace-nowrap ${low ? 'text-red-700' : ''}">${b.stok_saat_ini}</td>
            <td class="px-4 py-3 text-sm whitespace-nowrap">${b.satuan}</td>
            <td class="px-4 py-3 text-sm text-right mono whitespace-nowrap">${b.stok_minimum}</td>
            <td class="px-4 py-3 text-sm whitespace-nowrap">${low ? '<span class="bg-red-100 text-red-800 text-xs px-2 py-1 rounded">Menipis</span>' : '<span class="bg-blue-100 text-blue-800 text-xs px-2 py-1 rounded">Aman</span>'}</td>
          </tr>`;
        }).join('') || '<tr><td colspan="6" class="text-center py-12 text-stone-400"><svg class="w-14 h-14 mx-auto mb-3 text-stone-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z"/><polyline points="3.27 6.96 12 12.01 20.73 6.96"/><line x1="12" y1="22.08" x2="12" y2="12"/></svg><div>Belum ada bahan</div></td></tr>'}
        </tbody></table></div></div>`;
    } else {
      const endpoint = gudangState.tab === 'masuk' ? 'stok_masuk' : 'stok_keluar';
      const res = await api.get('/' + endpoint + '?' + params);
      const data = Array.isArray(res.data) ? res.data : (Array.isArray(res) ? res : []);
      const pagination = res.pagination || { total: data.length, totalPages: 1, page: 1 };
      gudangState = { ...gudangState, total: pagination.total, totalPages: pagination.totalPages, page: pagination.page };

      const labelKey = gudangState.tab === 'masuk' ? 'sumber' : 'tujuan';
      wrap.innerHTML = `<div class="bg-white border border-stone-200 rounded-lg overflow-hidden"><div class="overflow-x-auto"><table class="w-full">
        <thead class="bg-stone-50"><tr>
          <th class="text-left px-4 py-3 text-xs font-semibold uppercase whitespace-nowrap">Tanggal</th>
          <th class="text-left px-4 py-3 text-xs font-semibold uppercase whitespace-nowrap">Bahan</th>
          <th class="text-right px-4 py-3 text-xs font-semibold uppercase whitespace-nowrap">Jumlah</th>
          <th class="text-left px-4 py-3 text-xs font-semibold uppercase whitespace-nowrap">${gudangState.tab === 'masuk' ? 'Sumber' : 'Tujuan'}</th>
          <th class="text-left px-4 py-3 text-xs font-semibold uppercase whitespace-nowrap">Catatan</th>
        </tr></thead><tbody>${data.map(r => `<tr class="border-t border-stone-100">
          <td class="px-4 py-3 text-sm whitespace-nowrap">${fmtDate(r.tanggal)}</td>
          <td class="px-4 py-3 text-sm whitespace-nowrap">${r.nama_bahan}</td>
          <td class="px-4 py-3 text-sm text-right mono whitespace-nowrap">${r.jumlah} ${r.satuan}</td>
          <td class="px-4 py-3 text-sm whitespace-nowrap">${r[labelKey] || '-'}</td>
          <td class="px-4 py-3 text-sm whitespace-nowrap">${r.catatan || '-'}</td>
        </tr>`).join('') || '<tr><td colspan="5" class="text-center py-12 text-stone-400"><svg class="w-14 h-14 mx-auto mb-3 text-stone-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg><div>Belum ada riwayat</div></td></tr>'}
        </tbody></table></div></div>`;
    }

    renderGudangPagination();
  } catch (e) {
    wrap.innerHTML = `<div class="bg-red-50 border border-red-200 text-red-700 p-4 rounded-lg">Gagal: ${e.message}</div>`;
  }
}

function renderGudangPagination() {
  const wrap = document.getElementById('gudang-pagination');
  if (!wrap) return;
  if (gudangState.totalPages <= 1) { wrap.innerHTML = ''; return; }
  const prevBtn = gudangState.page > 1 ? `<button onclick="gudangGoToPage(${gudangState.page - 1})" class="px-2 py-1 text-sm rounded border border-stone-200 hover:bg-stone-50">Prev</button>` : '';
  const nextBtn = gudangState.page < gudangState.totalPages ? `<button onclick="gudangGoToPage(${gudangState.page + 1})" class="px-2 py-1 text-sm rounded border border-stone-200 hover:bg-stone-50">Next</button>` : '';
  wrap.innerHTML = `<span class="text-sm text-stone-500">Hal ${gudangState.page} dari ${gudangState.totalPages}</span>
    <div class="flex gap-2">${prevBtn}${nextBtn}</div>`;
}

function gudangGoToPage(page) {
  gudangState.page = page;
  loadGudang();
}
let _bahanListCache = null;
function openStokForm(tipe) {
  document.getElementById('modal-title').textContent = tipe === 'masuk' ? 'Barang Masuk' : 'Barang Keluar (Produksi)';
  document.getElementById('modal-save').style.display = '';
  if (!_bahanListCache) {
    api.get('/bahan_baku').then(list => { _bahanListCache = Array.isArray(list) ? list : []; });
  }
  const bahanList = _bahanListCache || [];
  document.getElementById('modal-body').innerHTML = `
    <div class="mb-3"><label class="text-sm">Tanggal</label>
      <input id="s-tanggal" type="date" value="${new Date().toISOString().slice(0,10)}" class="mt-1 w-full h-10 px-3 border border-stone-200 rounded-md" /></div>
    <div class="mb-3"><label class="text-sm">Bahan Baku</label>
      <select id="s-bahan" class="mt-1 w-full h-10 px-3 border border-stone-200 rounded-md">
        <option value="">— Pilih —</option>
        ${bahanList.map(b => `<option value="${b.id}">${b.nama} (stok: ${b.stok_saat_ini} ${b.satuan})</option>`).join('')}
      </select></div>
    <div class="mb-3"><label class="text-sm">Jumlah</label>
      <input id="s-jumlah" type="number" step="0.001" class="mt-1 w-full h-10 px-3 border border-stone-200 rounded-md mono" /></div>
    <div class="mb-3"><label class="text-sm">${tipe === 'masuk' ? 'Sumber / Supplier' : 'Tujuan (Produksi)'}</label>
      <input id="s-sumber" class="mt-1 w-full h-10 px-3 border border-stone-200 rounded-md" /></div>
    <div class="mb-3"><label class="text-sm">Catatan</label>
      <input id="s-catatan" class="mt-1 w-full h-10 px-3 border border-stone-200 rounded-md" /></div>`;
  document.getElementById('modal-save').onclick = async () => {
    try {
      if (!validateForm([
        { id: 's-tanggal', label: 'Tanggal' },
        { id: 's-bahan', label: 'Bahan Baku', type: 'select' },
        { id: 's-jumlah', label: 'Jumlah', type: 'number' }
      ])) return;
      const payload = {
        tanggal: document.getElementById('s-tanggal').value,
        bahan_baku_id: +document.getElementById('s-bahan').value,
        jumlah: +document.getElementById('s-jumlah').value,
        catatan: document.getElementById('s-catatan').value,
      };
      payload[tipe === 'masuk' ? 'sumber' : 'tujuan'] = document.getElementById('s-sumber').value;
      await api.post('/stok_' + tipe, payload);
      closeModal(); renderGudang();
    } catch (e) {
      console.error('Gudang submit error:', e);
      showAlert('Gagal: ' + (e.message || 'Unknown error'), 'error');
    }
  };
  document.getElementById('modal').classList.remove('hidden');
  document.getElementById('modal').classList.add('flex');
}

