// ===== Karyawan Helpers =====
let karyawanData = [];
let karyawanState = { page: 1, limit: 10, search: '', total: 0, totalPages: 1 };

async function loadKaryawan() {
  try {
    const params = new URLSearchParams({ page: karyawanState.page, limit: karyawanState.limit, search: karyawanState.search });
    const results = await Promise.allSettled([
      api.get('/karyawan?' + params),
      api.get('/departemen'),
      api.get('/jabatan')
    ]);
    const failed = results.find(r => r.status === 'rejected');
    if (failed) throw failed.reason;
    const res = results[0].value;
    const data = Array.isArray(res.data) ? res.data : (Array.isArray(res) ? res : []);
    const pagination = res.pagination || { total: data.length, totalPages: 1, page: 1 };
    karyawanState = { ...karyawanState, total: pagination.total, totalPages: pagination.totalPages, page: pagination.page };
    karyawanData = data;
    renderKaryawanTable(data);
    renderKaryawanPagination();
    const depts = results[1].value;
    const dd = document.getElementById('karyawan-departemen');
    if (dd) dd.innerHTML = '<option value="">— Pilih Departemen —</option>' + depts.map(d => `<option value="${d}">${d}</option>`).join('');
    const jabatanList = results[2].value;
    const jl = document.getElementById('karyawan-jabatan');
    if (jl) jl.innerHTML = '<option value="">— Pilih Jabatan —</option>' + jabatanList.map(j => `<option value="${j.id}">${j.name}</option>`).join('');
  } catch (e) {
    console.error('loadKaryawan error:', e);
    const tb = document.querySelector('#karyawan-modal')?.parentElement?.querySelector('tbody');
    if (tb) tb.innerHTML = `<tr><td colspan="7" class="text-center py-12 text-red-600">Gagal memuat karyawan: ${e.message}</td></tr>`;
  }
}
function renderKaryawanTable(list) {
  const tb = document.querySelector('#karyawan-modal').parentElement.querySelector('tbody');
  if (!list.length) { tb.innerHTML = '<tr><td colspan="7" class="text-center py-12 text-stone-400"><svg class="w-14 h-14 mx-auto mb-3 text-stone-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10"/><path d="M8 12h8"/></svg><div>Belum ada karyawan</div></td></tr>'; return; }
  tb.innerHTML = list.map(k => `
    <tr class="border-t border-stone-100">
      <td class="px-4 py-3 text-sm font-medium"><a href="/karyawan?id=${k.id}" onclick="event.preventDefault();navigate('karyawan?id=${k.id}')" class="text-[#1e40af] hover:underline">${k.nama}</a></td>
      <td class="px-4 py-3 text-sm">${k.nik || '-'}</td>
      <td class="px-4 py-3 text-sm">${k.jabatan_nama || '-'}</td>
      <td class="px-4 py-3 text-sm">${k.departemen || '-'}</td>
      <td class="px-4 py-3 text-sm text-right mono">${fmtIDR(k.gaji_pokok)}</td>
      <td class="px-4 py-3 text-sm">${k.status}</td>
      <td class="px-4 py-3 text-sm text-right whitespace-nowrap">
        <button onclick="openKaryawanForm(karyawanData.find(x => x.id == ${k.id}))" class="text-stone-500 hover:text-stone-900 mr-2" title="Edit"><svg class="w-4 h-4 inline" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg></button>
        <button onclick="deleteKaryawan(${k.id})" class="text-red-600 hover:text-red-800" title="Hapus"><svg class="w-4 h-4 inline" fill="none" stroke="currentColor" viewBox="0 0 24 24"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/></svg></button>
      </td>
    </tr>`).join('');
}

async function deleteKaryawan(id) {
  if (!await showConfirm('Hapus karyawan?')) return;
  await api.del('/karyawan/' + id);
  loadKaryawan();
}

function lihatAbsensiKaryawan(id) {
  window._absenFilterKaryawanId = id;
  navigate('absensi');
}

async function showKaryawanDetail(id) {
  const c = document.getElementById('content');
  c.innerHTML = '<div class="flex items-center justify-center py-24"><svg class="animate-spin h-10 w-10 text-[#1e40af]" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"/><path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"/></svg></div>';
  try {
    const r = await fetch(`/api/template/karyawan/${id}`, { credentials: 'include' });
    if (!r.ok) throw new Error((await r.json()).error || 'Gagal memuat detail');
    c.innerHTML = await r.text();
    document.getElementById('karyawan-save') && (document.getElementById('karyawan-save').onclick = saveKaryawan);
  } catch (e) {
    c.innerHTML = `<div class="text-center py-24 text-stone-400"><svg class="w-20 h-20 mx-auto mb-4 text-stone-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10"/><path d="M8 12h8"/><line x1="4.93" y1="4.93" x2="19.07" y2="19.07"/></svg><div class="text-lg font-medium">Karyawan tidak ditemukan</div><button onclick="navigate('karyawan')" class="mt-4 text-sm text-[#1e40af] hover:underline">&larr; Kembali ke daftar</button></div>`;
  }
}

function renderKaryawanPagination() {
  const wrap = document.getElementById('karyawan-pagination');
  if (!wrap) return;
  if (karyawanState.totalPages <= 1) { wrap.innerHTML = ''; return; }
  const prevBtn = karyawanState.page > 1 ? `<button onclick="kryGoToPage(${karyawanState.page - 1})" class="px-2 py-1 text-sm rounded border border-stone-200 hover:bg-stone-50">Prev</button>` : '';
  const nextBtn = karyawanState.page < karyawanState.totalPages ? `<button onclick="kryGoToPage(${karyawanState.page + 1})" class="px-2 py-1 text-sm rounded border border-stone-200 hover:bg-stone-50">Next</button>` : '';
  wrap.innerHTML = `<span class="text-sm text-stone-500">Hal ${karyawanState.page} dari ${karyawanState.totalPages}</span>
    <div class="flex gap-2">${prevBtn}${nextBtn}</div>`;
}
function kryGoToPage(p) {
  karyawanState.page = p;
  loadKaryawan();
}
function openKaryawanForm(k) {
  document.getElementById('karyawan-id').value = k ? k.id : '';
  document.getElementById('karyawan-nama').value = k ? k.nama : '';
  document.getElementById('karyawan-nik').value = k ? k.nik || '' : '';
  document.getElementById('karyawan-jabatan').value = k ? k.jabatan_id || '' : '';
  document.getElementById('karyawan-departemen').value = k ? k.departemen || '' : '';
  document.getElementById('karyawan-gaji').value = k ? k.gaji_pokok : '';
  document.getElementById('karyawan-status').value = k ? k.status : 'Aktif';
  document.getElementById('karyawan-masuk').value = k ? k.tanggal_masuk || '' : '';
  document.getElementById('karyawan-email').value = k ? k.email || '' : '';
  document.getElementById('karyawan-telepon').value = k ? k.phone || '' : '';
  document.getElementById('karyawan-alamat').value = k ? k.address || '' : '';
  document.getElementById('karyawan-modal-title').textContent = k ? 'Edit Karyawan' : 'Tambah Karyawan';
  window._karyawanCurrentPhoto = k ? k.photo : null;
  const jl = document.getElementById('karyawan-jabatan');
  if (jl && !jl.options.length) {
    api.get('/jabatan').then(function(list) {
      jl.innerHTML = '<option value="">— Pilih Jabatan —</option>' + list.map(function(j) { return '<option value="' + j.id + '">' + j.name + '</option>'; }).join('');
      if (k && k.jabatan_id) jl.value = k.jabatan_id;
    });
  }
  const dd = document.getElementById('karyawan-departemen');
  if (dd && !dd.options.length) {
    api.get('/departemen').then(function(list) {
      dd.innerHTML = '<option value="">— Pilih Departemen —</option>' + list.map(function(d) { return '<option value="' + d + '">' + d + '</option>'; }).join('');
      if (k && k.departemen) dd.value = k.departemen;
    });
  }
  const preview = document.getElementById('karyawan-photo-preview');
  const photoInput = document.getElementById('karyawan-photo-input');
  const hapusBtn = document.getElementById('karyawan-photo-hapus');
  if (preview) {
    if (k && k.photo) {
      preview.innerHTML = '<img src="' + k.photo + '" class="w-full h-full object-cover" />';
      if (hapusBtn) hapusBtn.classList.remove('hidden');
    } else {
      preview.innerHTML = '<svg class="w-6 h-6 text-stone-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"/></svg>';
      if (hapusBtn) hapusBtn.classList.add('hidden');
    }
  }
  if (photoInput) {
    photoInput.onchange = function() {
      const file = this.files[0];
      if (!file) return;
      const reader = new FileReader();
      reader.onload = function(e) {
        if (preview) preview.innerHTML = '<img src="' + e.target.result + '" class="w-full h-full object-cover" />';
        if (hapusBtn) hapusBtn.classList.remove('hidden');
      };
      reader.readAsDataURL(file);
    };
  }
  if (hapusBtn) {
    hapusBtn.onclick = function() {
      if (photoInput) photoInput.value = '';
      if (preview) preview.innerHTML = '<svg class="w-6 h-6 text-stone-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"/></svg>';
      hapusBtn.classList.add('hidden');
      window._karyawanCurrentPhoto = null;
    };
  }
  document.getElementById('karyawan-modal').classList.remove('hidden');
  document.getElementById('karyawan-modal').classList.add('flex');
}
async function saveKaryawan() {
  let karyawanId = document.getElementById('karyawan-id').value;
  const payload = {
    nama: document.getElementById('karyawan-nama').value,
    nik: document.getElementById('karyawan-nik').value,
    jabatan_id: document.getElementById('karyawan-jabatan').value || null,
    departemen: document.getElementById('karyawan-departemen').value,
    gaji_pokok: +(document.getElementById('karyawan-gaji').value || 0),
    status: document.getElementById('karyawan-status').value,
    tanggal_masuk: document.getElementById('karyawan-masuk').value,
    email: document.getElementById('karyawan-email').value,
    phone: document.getElementById('karyawan-telepon').value,
    address: document.getElementById('karyawan-alamat').value,
  };
  const fileInput = document.getElementById('karyawan-photo-input');
  if (fileInput && fileInput.files.length) {
    payload.photo = await new Promise(function(resolve) {
      var reader = new FileReader();
      reader.onload = function() { resolve(reader.result); };
      reader.readAsDataURL(fileInput.files[0]);
    });
  } else if (window._karyawanCurrentPhoto === null) {
    payload.photo = null;
  }
  if (!validateForm([{ id: 'karyawan-nama', label: 'Nama Karyawan' }])) return;
  const isEdit = !!karyawanId;
  try {
    if (isEdit) await api.put('/karyawan/' + karyawanId, payload);
    else { const newRow = await api.post('/karyawan', payload); karyawanId = newRow.id; }
  } catch (e) { showAlert('Gagal: ' + (e.message || ''), 'error'); return; }
  document.getElementById('karyawan-modal').classList.add('hidden');
  document.getElementById('karyawan-modal').classList.remove('flex');
  showToast('Karyawan berhasil ' + (isEdit ? 'diperbarui' : 'disimpan'), 'success');
  if (new URLSearchParams(location.search).get('id')) {
    navigate('karyawan?id=' + karyawanId);
  } else {
    loadKaryawan();
  }
}

// ===== Absensi Helpers =====
let karyawanOptions = [];
async function loadKaryawanOptions() {
  try {
    const rows = await api.get('/karyawan?status=Aktif');
    karyawanOptions = Array.isArray(rows) ? rows : [];
    const opts = '<option value="">Semua Karyawan</option>' +
      karyawanOptions.map(k => `<option value="${k.id}">${k.nama} - ${k.jabatan_nama || '-'}</option>`).join('');
    const paySel = document.getElementById('pay-filter-karyawan');
    if (paySel) paySel.innerHTML = opts;
    const absSel = document.getElementById('abs-filter-karyawan');
    if (absSel) absSel.innerHTML = opts;
    const absFormSel = document.getElementById('absensi-karyawan');
    if (absFormSel) absFormSel.innerHTML = '<option value="">— Pilih —</option>' +
      karyawanOptions.map(k => `<option value="${k.id}">${k.nama} - ${k.jabatan_nama || '-'}</option>`).join('');
  } catch (e) {
    console.error('loadKaryawanOptions error:', e);
    karyawanOptions = [];
  }
}
async function loadAbsensi(page = 1) {
  const params = new URLSearchParams();
  const fk = document.getElementById('abs-filter-karyawan').value;
  const fta = document.getElementById('abs-filter-tanggal-awal').value;
  const ftb = document.getElementById('abs-filter-tanggal-akhir').value;
  const fs = document.getElementById('abs-filter-status').value;
  if (fk) params.set('karyawan_id', fk);
  if (fta) params.set('tanggal_awal', fta);
  if (ftb) params.set('tanggal_akhir', ftb);
  if (fs) params.set('status', fs);
  params.set('page', page);
  const res = await api.get('/absensi?' + params);
  renderAbsensiTable(res.data, res);
}
function renderAbsensiTable(list, pagination) {
  const tb = document.querySelector('#absensi-modal').parentElement.querySelector('tbody');
  if (!list.length) { tb.innerHTML = '<tr><td colspan="8" class="text-center py-12 text-stone-400"><svg class="w-14 h-14 mx-auto mb-3 text-stone-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg><div>Belum ada data absensi</div></td></tr>'; } else {
    tb.innerHTML = list.map(a => `
      <tr class="border-t border-stone-100">
        <td class="px-4 py-3 text-sm whitespace-nowrap">${fmtDate(a.tanggal)}</td>
        <td class="px-4 py-3 text-sm font-medium">${a.nama_karyawan}</td>
        <td class="px-4 py-3 text-sm">${a.jabatan || '-'}</td>
        <td class="px-4 py-3 text-sm text-center">${a.status}</td>
        <td class="px-4 py-3 text-sm text-center mono">${a.jam_masuk || '-'}</td>
        <td class="px-4 py-3 text-sm text-center mono">${a.jam_keluar || '-'}</td>
        <td class="px-4 py-3 text-sm">${a.keterangan || '-'}</td>
        <td class="px-4 py-3 text-sm text-right whitespace-nowrap">
          <button data-id="${a.id}" class="edit-absensi text-stone-500 hover:text-stone-900 mr-2" title="Edit"><svg class="w-4 h-4 inline" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg></button>
          <button data-id="${a.id}" class="delete-absensi text-red-600 hover:text-red-800" title="Hapus"><svg class="w-4 h-4 inline" fill="none" stroke="currentColor" viewBox="0 0 24 24"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"/></svg></button>
        </td>
      </tr>`).join('');
    tb.querySelectorAll('.edit-absensi').forEach(b => b.onclick = () => openAbsensiForm(list.find(x => x.id == b.dataset.id)));
    tb.querySelectorAll('.delete-absensi').forEach(b => b.onclick = async () => {
      if (!await showConfirm('Hapus data absensi?')) return;
      await api.del('/absensi/' + b.dataset.id);
      loadAbsensi(pagination?.page || 1);
    });
  }
  const pg = document.getElementById('absensi-pagination');
  if (pg && pagination) {
    pg.innerHTML = `<span>${pagination.total} data</span><div class="flex gap-1">${pagination.totalPages > 1 ? Array.from({ length: pagination.totalPages }, (_, i) => `<button onclick="loadAbsensi(${i + 1})" class="px-3 py-1 rounded ${i + 1 === pagination.page ? 'bg-[#1e40af] text-white' : 'bg-stone-100 hover:bg-stone-200'}">${i + 1}</button>`).join('') : ''}</div>`;
  }
}
function openAbsensiForm(a) {
  document.getElementById('absensi-id').value = a ? a.id : '';
  document.getElementById('absensi-karyawan').value = a ? a.karyawan_id : '';
  document.getElementById('absensi-tanggal').value = a ? a.tanggal : new Date().toISOString().slice(0,10);
  document.getElementById('absensi-status').value = a ? a.status : 'Hadir';
  document.getElementById('absensi-masuk').value = a ? a.jam_masuk || '' : '';
  document.getElementById('absensi-keluar').value = a ? a.jam_keluar || '' : '';
  document.getElementById('absensi-keterangan').value = a ? a.keterangan || '' : '';
  document.getElementById('absensi-modal-title').textContent = a ? 'Edit Absensi' : 'Input Absensi';
  const sel = document.getElementById('absensi-karyawan');
  sel.innerHTML = '<option value="">— Pilih —</option>' +
    (karyawanOptions || []).map(k => `<option value="${k.id}">${k.nama} - ${k.jabatan_nama || '-'}</option>`).join('');
  document.getElementById('absensi-modal').classList.remove('hidden');
  document.getElementById('absensi-modal').classList.add('flex');
}
function saveAbsensi() {
  const id = document.getElementById('absensi-id').value;
  const payload = {
    karyawan_id: +(document.getElementById('absensi-karyawan').value || 0),
    tanggal: document.getElementById('absensi-tanggal').value,
    status: document.getElementById('absensi-status').value,
    jam_masuk: document.getElementById('absensi-masuk').value,
    jam_keluar: document.getElementById('absensi-keluar').value,
    keterangan: document.getElementById('absensi-keterangan').value,
  };
  if (!validateForm([{ id: 'absensi-karyawan', label: 'Karyawan', type: 'select' }, { id: 'absensi-tanggal', label: 'Tanggal' }])) return;
  const isEdit = !!id;
  if (isEdit) {
    api.put('/absensi/' + id, payload).then(() => loadAbsensi());
  } else {
    api.post('/absensi', payload).then(() => loadAbsensi());
  }
  document.getElementById('absensi-modal').classList.add('hidden');
  document.getElementById('absensi-modal').classList.remove('flex');
}

// ===== Payroll Helpers =====
let payrollListGlobal = [];
async function loadPayroll() {
  const params = new URLSearchParams();
  const fk = document.getElementById('pay-filter-karyawan').value;
  const fp = document.getElementById('pay-filter-periode').value;
  const fs = document.getElementById('pay-filter-status').value;
  if (fk) params.set('karyawan_id', fk);
  if (fp) { const [tahun, bulan] = fp.split('-'); params.set('tahun', tahun); params.set('bulan', String(parseInt(bulan))); }
  if (fs) params.set('status', fs);
  payrollListGlobal = await api.get('/payroll?' + params);
  renderPayrollTable(payrollListGlobal);
}
function renderPayrollTable(list) {
  const tb = document.querySelector('#payroll-modal').parentElement.querySelector('tbody');
  if (!list.length) { tb.innerHTML = '<tr><td colspan="9" class="text-center py-12 text-stone-400"><svg class="w-14 h-14 mx-auto mb-3 text-stone-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><rect x="2" y="7" width="20" height="14" rx="2" ry="2"/><path d="M16 21V5a2 2 0 0 0-2-2h-4a2 2 0 0 0-2 2v16"/></svg><div>Belum ada data payroll</div></td></tr>'; return; }
  const BLN = ['','Januari','Februari','Maret','April','Mei','Juni','Juli','Agustus','September','Oktober','November','Desember'];
  tb.innerHTML = list.map(p => `
    <tr class="border-t border-stone-100">
      <td class="px-4 py-3 text-sm whitespace-nowrap">${BLN[p.bulan]} ${p.tahun}</td>
      <td class="px-4 py-3 text-sm font-medium">${p.nama_karyawan}</td>
      <td class="px-4 py-3 text-sm">${p.jabatan || '-'}</td>
      <td class="px-4 py-3 text-sm text-right mono">${fmtIDR(p.gaji_pokok)}</td>
      <td class="px-4 py-3 text-sm text-right mono">${fmtIDR(p.tunjangan)}</td>
      <td class="px-4 py-3 text-sm text-right mono">${fmtIDR(p.potongan)}</td>
      <td class="px-4 py-3 text-sm text-right mono font-medium">${fmtIDR(p.total_gaji)}</td>
      <td class="px-4 py-3 text-sm text-center">${p.status}</td>
      <td class="px-4 py-3 text-sm text-right whitespace-nowrap">
        <button data-id="${p.id}" class="edit-payroll text-stone-500 hover:text-stone-900 mr-2">Edit</button>
        <button data-id="${p.id}" class="text-red-600">Hapus</button>
      </td>
    </tr>`).join('');
  tb.querySelectorAll('.edit-payroll').forEach(b => b.onclick = () => openPayrollForm(payrollListGlobal.find(x => x.id == b.dataset.id)));
  tb.querySelectorAll('.text-red-600').forEach(b => b.onclick = async () => {
    if (!await showConfirm('Hapus data payroll?')) return;
    await api.del('/payroll/' + b.dataset.id);
    loadPayroll();
  });
}
function openPayrollForm(p) {
  document.getElementById('payroll-id').value = p ? p.id : '';
  document.getElementById('payroll-karyawan').value = p ? p.karyawan_id : '';
  const now = new Date();
  const tahun = p ? p.tahun : now.getFullYear();
  const bulan = p ? String(p.bulan).padStart(2, '0') : String(now.getMonth() + 1).padStart(2, '0');
  document.getElementById('payroll-periode').value = tahun + '-' + bulan + '-01';
  document.getElementById('payroll-gaji').value = p ? p.gaji_pokok : '';
  document.getElementById('payroll-tunjangan').value = p ? p.tunjangan : '';
  document.getElementById('payroll-potongan').value = p ? p.potongan : '';
  document.getElementById('payroll-status').value = p ? p.status : 'Draft';
  document.getElementById('payroll-modal-title').textContent = p ? 'Edit Payroll' : 'Tambah Payroll';
  const sel = document.getElementById('payroll-karyawan');
  sel.innerHTML = (karyawanOptions || []).map(k => `<option value="${k.id}">${k.nama} - ${k.jabatan_nama || '-'}</option>`).join('');
  document.getElementById('payroll-modal').classList.remove('hidden');
  document.getElementById('payroll-modal').classList.add('flex');
}
function savePayroll() {
  const id = document.getElementById('payroll-id').value;
  const periode = document.getElementById('payroll-periode').value;
  const [thn, bln] = periode ? periode.split('-') : [];
  const payload = {
    karyawan_id: +(document.getElementById('payroll-karyawan').value || 0),
    bulan: +(bln || 0),
    tahun: +(thn || 0),
    gaji_pokok: +(document.getElementById('payroll-gaji').value || 0),
    tunjangan: +(document.getElementById('payroll-tunjangan').value || 0),
    potongan: +(document.getElementById('payroll-potongan').value || 0),
    status: document.getElementById('payroll-status').value,
  };
  if (!validateForm([{ id: 'payroll-karyawan', label: 'Karyawan', type: 'select' }])) return;
  const isEdit = !!id;
  if (isEdit) {
    api.put('/payroll/' + id, payload).then(() => loadPayroll());
  } else {
    api.post('/payroll', payload).then(() => loadPayroll());
  }
  document.getElementById('payroll-modal').classList.add('hidden');
  document.getElementById('payroll-modal').classList.remove('flex');
}

// ===== Shift — Jadwal Kerja per Divisi =====
async function renderShift() {
  const c = document.getElementById('content');
  c.innerHTML = '<div class="flex items-center justify-center py-24"><svg class="animate-spin h-10 w-10 text-[#1e40af]" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"/><path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"/></svg></div>';
  try {
    const r = await fetch('/api/template/shift', { credentials: 'include' });
    if (!r.ok) { const err = await r.json(); throw new Error(err.error || 'Gagal memuat shift'); }
    c.innerHTML = await r.text();
    attachShiftHandlers();
    reloadJadwal();
  } catch (err) {
    console.error('Shift error:', err);
    c.innerHTML = '<div class="bg-red-50 border border-red-200 text-red-700 p-4 rounded-lg">Gagal memuat shift: ' + err.message + '</div>';
  }
}

function attachShiftHandlers() {
  document.getElementById('add-shift-btn').onclick = function() { openShiftForm(null); };
  document.getElementById('add-jadwal-btn').onclick = function() { openJadwalForm(null); };
  var filterDept = document.getElementById('shift-filter-departemen');
  if (filterDept) filterDept.onchange = function() { filterShiftTable(this.value); };
}

function filterShiftTable(dept) {
  document.querySelectorAll('#shift-table-body tr').forEach(function(tr) {
    var td = tr.querySelector('td:first-child span');
    if (!td) return;
    tr.style.display = (!dept || td.textContent.trim() === dept) ? '' : 'none';
  });
}

async function openShiftForm(editing) {
  var jabatanList = await api.get('/jabatan');
  var s = editing || { nama: '', departemen: '', jam_masuk: '08:00', jam_keluar: '16:00', warna: '#3B82F6' };
  document.getElementById('modal-title').textContent = editing ? 'Edit Shift' : 'Shift Baru';
  document.getElementById('modal-body').innerHTML =
    '<div class="space-y-4">' +
    '<div class="grid grid-cols-2 gap-3">' +
    '<div><label class="text-sm font-medium text-stone-700">Nama Shift *</label><input id="sf-nama" value="' + s.nama + '" placeholder="cth: Shift Pagi" class="mt-1 w-full h-10 px-3 border border-stone-200 rounded-md" /></div>' +
    '<div><label class="text-sm font-medium text-stone-700">Departemen *</label><select id="sf-dept" class="mt-1 w-full h-10 px-3 border border-stone-200 rounded-md"><option value="">— Pilih Departemen —</option>' +
    jabatanList.map(function(j) { return '<option value="' + j.name + '" ' + (s.departemen === j.name ? 'selected' : '') + '>' + j.name + '</option>'; }).join('') +
    '</select></div>' +
    '</div>' +
    '<div class="grid grid-cols-2 gap-3">' +
    '<div><label class="text-sm font-medium text-stone-700">Jam Masuk *</label><input id="sf-masuk" type="time" value="' + s.jam_masuk + '" class="mt-1 w-full h-10 px-3 border border-stone-200 rounded-md" /></div>' +
    '<div><label class="text-sm font-medium text-stone-700">Jam Keluar *</label><input id="sf-keluar" type="time" value="' + s.jam_keluar + '" class="mt-1 w-full h-10 px-3 border border-stone-200 rounded-md" /></div>' +
    '</div>' +
    '<div><label class="text-sm font-medium text-stone-700">Warna (opsional)</label><div class="flex items-center gap-2 mt-1"><input id="sf-warna" type="color" value="' + s.warna + '" class="h-10 w-14 rounded border border-stone-200 cursor-pointer" /><span class="text-xs text-stone-500">' + s.warna + '</span></div></div>' +
    '</div>';

  document.getElementById('modal-save').onclick = async function() {
    var nama = document.getElementById('sf-nama').value.trim();
    var dept = document.getElementById('sf-dept').value.trim();
    var masuk = document.getElementById('sf-masuk').value;
    var keluar = document.getElementById('sf-keluar').value;
    var warna = document.getElementById('sf-warna').value;
    if (!nama) { showAlert('Nama shift harus diisi', 'warning'); return; }
    if (!dept) { showAlert('Departemen harus diisi', 'warning'); return; }
    if (!masuk || !keluar) { showAlert('Jam masuk dan jam keluar harus diisi', 'warning'); return; }
    try {
      var payload = { nama: nama, departemen: dept, jam_masuk: masuk, jam_keluar: keluar, warna: warna };
      if (editing) await api.put('/shift/' + editing.id, payload);
      else await api.post('/shift', payload);
      closeModal(); renderShift();
    } catch (e) { showAlert('Gagal: ' + (e.message || 'Unknown error'), 'error'); }
  };
  document.getElementById('modal').classList.remove('hidden');
  document.getElementById('modal').classList.add('flex');
}

window.editShift = async function(id) {
  var list = await api.get('/shift');
  var s = list.find(function(x) { return x.id == id; });
  if (s) openShiftForm(s);
};

window.deleteShift = async function(id) {
  if (!await showConfirm('Hapus shift ini?')) return;
  await api.del('/shift/' + id);
  renderShift();
};

// ===== Jadwal Karyawan =====
var jadwalData = [];

async function reloadJadwal() {
  try {
    jadwalData = await api.get('/jadwal');
    renderJadwalTable(jadwalData);
  } catch (e) {
    var wrap = document.getElementById('jadwal-content');
    if (wrap) wrap.innerHTML = '<div class="text-center py-12 text-red-600">Gagal memuat jadwal</div>';
  }
}

function renderJadwalTable(list) {
  var wrap = document.getElementById('jadwal-content');
  if (!wrap) return;
  if (!list.length) {
    wrap.innerHTML = '<div class="text-center py-12 text-stone-400"><svg class="w-14 h-14 mx-auto mb-3 text-stone-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg><div>Belum ada jadwal shift.</div></div>';
    return;
  }
  var HARI = ['', 'Senin', 'Selasa', 'Rabu', 'Kamis', 'Jumat', 'Sabtu', 'Minggu'];
  var rowsHtml = list.map(function(j) {
    var hariArr = (j.hari_kerja || '1,2,3,4,5,6,7').split(',').map(function(h) { return HARI[parseInt(h)] || ''; }).filter(Boolean);
    var hariLabel = hariArr.length >= 7 ? 'Setiap hari' : (hariArr.length === 5 && hariArr[0] === 'Senin' && hariArr[4] === 'Jumat' ? 'Sen-Jum' : hariArr.slice(0,3).join(',') + (hariArr.length > 3 ? '...' : ''));
    return '<tr class="border-t border-stone-100">' +
      '<td class="px-4 py-3 text-sm font-medium">' + (j.nama_karyawan || '—') + '</td>' +
      '<td class="px-4 py-3 text-sm"><span class="px-2 py-0.5 rounded text-xs font-medium" style="background:' + (j.warna || '#3B82F6') + '20;color:' + (j.warna || '#3B82F6') + '">' + (j.shift_nama || '—') + '</span></td>' +
      '<td class="px-4 py-3 text-sm">' + (j.shift_departemen || '—') + '</td>' +
      '<td class="px-4 py-3 text-sm text-center mono">' + (j.jam_masuk ? j.jam_masuk.slice(0,5) : '—') + ' - ' + (j.jam_keluar ? j.jam_keluar.slice(0,5) : '—') + '</td>' +
      '<td class="px-4 py-3 text-sm text-center">' + (j.tanggal_mulai || '—') + '</td>' +
      '<td class="px-4 py-3 text-sm text-center">' + (j.tanggal_selesai || '—') + '</td>' +
      '<td class="px-4 py-3 text-sm text-center">' + hariLabel + '</td>' +
      '<td class="px-4 py-3 text-sm text-right whitespace-nowrap"><button onclick="editJadwal(' + j.id + ')" class="text-stone-500 hover:text-stone-900 mr-2">Edit</button><button onclick="deleteJadwal(' + j.id + ')" class="text-red-600">Hapus</button></td></tr>';
  }).join('');
  wrap.innerHTML = '<div class="overflow-x-auto"><table class="w-full"><thead class="bg-stone-50"><tr>' +
    '<th class="text-left px-4 py-3 text-xs font-semibold uppercase">Karyawan</th>' +
    '<th class="text-left px-4 py-3 text-xs font-semibold uppercase">Shift</th>' +
    '<th class="text-left px-4 py-3 text-xs font-semibold uppercase">Departemen</th>' +
    '<th class="text-center px-4 py-3 text-xs font-semibold uppercase">Jam</th>' +
    '<th class="text-center px-4 py-3 text-xs font-semibold uppercase">Mulai</th>' +
    '<th class="text-center px-4 py-3 text-xs font-semibold uppercase">Selesai</th>' +
    '<th class="text-center px-4 py-3 text-xs font-semibold uppercase">Hari</th>' +
    '<th class="text-right px-4 py-3 text-xs font-semibold uppercase">Aksi</th></tr></thead><tbody>' +
    rowsHtml + '</tbody></table></div>';
}

async function openJadwalForm(editing) {
  var shiftList = await api.get('/shift');
  var karyawanList = await api.get('/karyawan?status=Aktif');
  var j = editing || { karyawan_id: '', shift_id: '', tanggal_mulai: new Date().toISOString().slice(0,10), tanggal_selesai: '', hari_kerja: '1,2,3,4,5,6,7' };
  document.getElementById('modal-title').textContent = editing ? 'Edit Jadwal Shift' : 'Atur Jadwal Shift';
  document.getElementById('modal-body').innerHTML =
    '<div class="space-y-4">' +
    '<div><label class="text-sm font-medium text-stone-700">Karyawan *</label><select id="jd-karyawan" class="mt-1 w-full h-10 px-3 border border-stone-200 rounded-md"><option value="">— Pilih Karyawan —</option>' +
    karyawanList.map(function(k) { return '<option value="' + k.id + '" ' + (j.karyawan_id == k.id ? 'selected' : '') + '>' + k.nama + ' — ' + (k.jabatan_nama || '-') + '</option>'; }).join('') +
    '</select></div>' +
    '<div><label class="text-sm font-medium text-stone-700">Shift *</label><select id="jd-shift" class="mt-1 w-full h-10 px-3 border border-stone-200 rounded-md"><option value="">— Pilih Shift —</option>' +
    shiftList.map(function(s) { return '<option value="' + s.id + '" ' + (j.shift_id == s.id ? 'selected' : '') + '>' + s.departemen + ' — ' + s.nama + ' (' + s.jam_masuk.slice(0,5) + '-' + s.jam_keluar.slice(0,5) + ')</option>'; }).join('') +
    '</select></div>' +
    '<div class="grid grid-cols-2 gap-3">' +
    '<div><label class="text-sm font-medium text-stone-700">Tanggal Mulai *</label><input id="jd-mulai" type="date" value="' + j.tanggal_mulai + '" class="mt-1 w-full h-10 px-3 border border-stone-200 rounded-md" /></div>' +
    '<div><label class="text-sm font-medium text-stone-700">Tanggal Selesai</label><input id="jd-selesai" type="date" value="' + (j.tanggal_selesai || '') + '" class="mt-1 w-full h-10 px-3 border border-stone-200 rounded-md" /><div class="text-xs text-stone-400 mt-1">Kosongkan jika tidak ada batas</div></div>' +
    '</div></div>';

  document.getElementById('modal-save').onclick = async function() {
    var karyawan_id = document.getElementById('jd-karyawan').value;
    var shift_id = document.getElementById('jd-shift').value;
    var mulai = document.getElementById('jd-mulai').value;
    var selesai = document.getElementById('jd-selesai').value;
    if (!karyawan_id) { showAlert('Pilih karyawan', 'warning'); return; }
    if (!shift_id) { showAlert('Pilih shift', 'warning'); return; }
    if (!mulai) { showAlert('Tanggal mulai harus diisi', 'warning'); return; }
    try {
      var payload = { karyawan_id: +karyawan_id, shift_id: +shift_id, tanggal_mulai: mulai, tanggal_selesai: selesai || null, hari_kerja: '1,2,3,4,5,6,7' };
      if (editing) await api.put('/jadwal/' + editing.id, payload);
      else await api.post('/jadwal', payload);
      closeModal(); renderShift();
    } catch (e) { showAlert('Gagal: ' + (e.message || 'Unknown error'), 'error'); }
  };
  document.getElementById('modal').classList.remove('hidden');
  document.getElementById('modal').classList.add('flex');
}

window.editJadwal = async function(id) {
  try {
    var j = await api.get('/jadwal/' + id);
    if (j) openJadwalForm(j);
  } catch(e) { showAlert('Gagal memuat jadwal', 'error'); }
};

window.deleteJadwal = async function(id) {
  if (!await showConfirm('Hapus jadwal ini?')) return;
  await api.del('/jadwal/' + id);
  reloadJadwal();
};

// init() dan preloadMenus() dipindah ke inti.js
async function renderAkun() {
  const c = document.getElementById('content');
  c.innerHTML = '<div class="flex items-center justify-center py-24"><svg class="animate-spin h-10 w-10 text-[#1e40af]" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"/><path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"/></svg></div>';
  try {
    const r = await fetch('/api/template/akun', { credentials: 'include' });
    if (!r.ok) throw new Error((await r.json()).error || 'Gagal memuat');
    c.innerHTML = await r.text();

    let fotoBase64 = null;
    const fotoInput = document.getElementById('foto-input');
    const fotoPreview = document.getElementById('foto-preview');
    const fotoInitials = document.getElementById('foto-initials');
    const hapusBtn = document.getElementById('btn-hapus-foto');

    fotoInput.onchange = function() {
      const file = this.files[0];
      if (!file) return;
      if (file.size > 2 * 1024 * 1024) return showAlert('Maks 2MB', 'warning');
      const reader = new FileReader();
      reader.onload = function(e) {
        fotoBase64 = e.target.result;
        fotoPreview.innerHTML = '<img src="' + fotoBase64 + '" class="w-full h-full object-cover" />';
        hapusBtn.classList.remove('hidden');
      };
      reader.readAsDataURL(file);
    };

    hapusBtn.onclick = function() {
      fotoBase64 = 'hapus';
      fotoPreview.innerHTML = '<span id="foto-initials" class="text-3xl font-bold text-stone-400">' + (document.getElementById('akun-nama').value.split(' ').map(function(w) { return w[0]; }).filter(Boolean).slice(0, 2).join('').toUpperCase() || '?') + '</span>';
      hapusBtn.classList.add('hidden');
    };

    document.getElementById('btn-simpan-profil').onclick = async function() {
      var nama = document.getElementById('akun-nama').value.trim();
      var email = document.getElementById('akun-email').value.trim();
      if (!nama) return showAlert('Nama tidak boleh kosong', 'warning');
      if (!email) return showAlert('Email tidak boleh kosong', 'warning');
      try {
        var payload = { nama: nama, email: email };
        if (fotoBase64) payload.foto = fotoBase64;
        var res = await api.put('/auth/profile', payload);
        document.getElementById('user-name').textContent = nama;
        if (res.user && res.user.foto) {
          document.getElementById('user-avatar').innerHTML = '<img src="' + res.user.foto + '" class="w-full h-full object-cover" />';
        }
        fotoBase64 = null;
        showToast('Profil berhasil diperbarui', 'success');
      } catch (e) {
        showAlert(e.message || 'Gagal simpan profil', 'error');
      }
    };

    document.getElementById('btn-ganti-password').onclick = async function() {
      var password_lama = document.getElementById('akun-pass-lama').value;
      var password_baru = document.getElementById('akun-pass-baru').value;
      if (!password_lama) return showAlert('Masukkan password lama', 'warning');
      if (!password_baru || password_baru.length < 6) return showAlert('Password baru minimal 6 karakter', 'warning');
      try {
        await api.put('/auth/password', { password_lama: password_lama, password_baru: password_baru });
        document.getElementById('akun-pass-lama').value = '';
        document.getElementById('akun-pass-baru').value = '';
        showToast('Password berhasil diganti', 'success');
      } catch (e) {
        showAlert(e.message || 'Gagal ganti password', 'error');
      }
    };
  } catch (err) {
    c.innerHTML = '<div class="bg-red-50 border border-red-200 text-red-700 p-4 rounded-lg">Gagal memuat: ' + err.message + '</div>';
  }
}let userEditing = null;

async function renderKelolaUser() {
  const c = document.getElementById('content');
  c.innerHTML = '<div class="flex items-center justify-center py-24"><svg class="animate-spin h-10 w-10 text-[#1e40af]" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"/><path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"/></svg></div>';
  try {
    const r = await fetch('/api/template/kelola-user', { credentials: 'include' });
    if (!r.ok) throw new Error((await r.json()).error || 'Gagal memuat');
    c.innerHTML = await r.text();
    document.getElementById('btn-tambah-user').onclick = () => openUserForm(null);
    document.getElementById('btn-simpan-user').onclick = simpanUser;
    loadUsers();
  } catch (err) {
    c.innerHTML = '<div class="bg-red-50 border border-red-200 text-red-700 p-4 rounded-lg">Gagal memuat: ' + err.message + '</div>';
  }
}

async function loadUsers() {
  try {
    const rows = await api.get('/users');
    const tbody = document.getElementById('user-table-body');
    if (!rows.length) {
      tbody.innerHTML = '<tr><td colspan="5" class="text-center py-12 text-stone-400">Belum ada user</td></tr>';
      return;
    }
    tbody.innerHTML = rows.map(function(u) {
      var tanggal = u.created_at ? new Date(u.created_at).toLocaleDateString('id-ID', { year: 'numeric', month: 'short', day: 'numeric' }) : '-';
      return '<tr class="border-t border-stone-100">' +
        '<td class="px-4 py-3 text-sm">' + (u.nama || '') + '</td>' +
        '<td class="px-4 py-3 text-sm text-stone-500">' + (u.email || '') + '</td>' +
        '<td class="px-4 py-3 text-sm capitalize">' + u.role.replace('_', ' ') + '</td>' +
        '<td class="px-4 py-3 text-sm text-stone-500">' + tanggal + '</td>' +
        '<td class="px-4 py-3 text-sm text-right whitespace-nowrap">' +
          '<button onclick="openUserForm(' + u.id + ')" class="text-blue-600 hover:text-blue-800 text-xs font-medium mr-3">Edit</button>' +
          '<button onclick="hapusUser(' + u.id + ')" class="text-red-600 hover:text-red-800 text-xs font-medium">Hapus</button>' +
        '</td></tr>';
    }).join('');
  } catch (e) {
    showAlert('Gagal load user: ' + e.message, 'error');
  }
}

function openUserForm(id) {
  userEditing = id;
  document.getElementById('user-modal-title').textContent = id ? 'Edit User' : 'Tambah User';
  document.getElementById('user-id').value = id || '';
  document.getElementById('user-nama').value = '';
  document.getElementById('user-email').value = '';
  document.getElementById('user-password').value = '';
  document.getElementById('user-role').value = 'produksi';
  var passLabel = document.getElementById('pass-label');
  if (id) {
    passLabel.textContent = '(kosongkan jika tidak diganti)';
    // Load existing data via API
    api.get('/users').then(function(rows) {
      var u = rows.find(function(r) { return r.id === id; });
      if (!u) return;
      document.getElementById('user-nama').value = u.nama;
      document.getElementById('user-email').value = u.email;
      document.getElementById('user-role').value = u.role;
    });
  } else {
    passLabel.textContent = '*';
  }
  document.getElementById('user-modal').classList.remove('hidden');
  document.getElementById('user-modal').classList.add('flex');
}

function closeUserModal() {
  document.getElementById('user-modal').classList.add('hidden');
  document.getElementById('user-modal').classList.remove('flex');
}

async function simpanUser() {
  var id = document.getElementById('user-id').value;
  var nama = document.getElementById('user-nama').value.trim();
  var email = document.getElementById('user-email').value.trim();
  var password = document.getElementById('user-password').value;
  var role = document.getElementById('user-role').value;
  if (!nama) return showAlert('Nama wajib diisi', 'warning');
  if (!email) return showAlert('Email wajib diisi', 'warning');
  if (!id && (!password || password.length < 6)) return showAlert('Password minimal 6 karakter', 'warning');
  try {
    if (id) {
      var payload = { nama: nama, email: email, role: role };
      if (password) payload.password = password;
      await api.put('/users/' + id, payload);
      showToast('User diperbarui', 'success');
    } else {
      await api.post('/users', { nama: nama, email: email, password: password, role: role });
      showToast('User ditambahkan', 'success');
    }
    closeUserModal();
    loadUsers();
  } catch (e) {
    showAlert(e.message || 'Gagal simpan user', 'error');
  }
}

async function hapusUser(id) {
  if (!await showConfirm('Hapus user ini?')) return;
  try {
    await api.del('/users/' + id);
    showToast('User dihapus', 'success');
    loadUsers();
  } catch (e) {
    showAlert(e.message || 'Gagal hapus user', 'error');
  }
}async function renderPembelian() {
  const cfg = {
    endpoint: '/purchase_order',
    fields: [
      { k: 'no_po', l: 'Nomor PO', req: true },
      { k: 'tanggal', l: 'Tanggal', type: 'date', req: true },
      { k: 'supplier_nama', l: 'Supplier' },
      { k: 'item', l: 'Daftar Item', type: 'textarea' },
      { k: 'total_nilai', l: 'Total Nilai (IDR)', type: 'number', fmt: 'idr' },
      { k: 'status', l: 'Status', type: 'select', opts: ['Draft','Disetujui','Dikirim','Diterima','Dibayar'] },
      { k: 'catatan', l: 'Catatan', type: 'textarea' },
    ],
    cols: ['no_po', 'tanggal', 'supplier_nama', 'total_nilai', 'status'],
  };

  await renderCrud(cfg);

  const toolbar = document.querySelector('#content > div:first-child');
  if (!toolbar) return;
  const group = document.createElement('div');
  group.className = 'flex gap-2';
  const btn = document.createElement('button');
  btn.id = 'po-from-siklus-btn';
  btn.className = 'bg-orange-600 hover:bg-orange-700 text-white px-4 py-2 rounded-md text-sm font-medium';
  btn.textContent = '+ Buat dari Siklus';
  btn.onclick = openSiklusPicker;
  const addBtn = document.getElementById('add-btn');
  toolbar.insertBefore(group, toolbar.firstChild);
  group.appendChild(btn);
  if (addBtn) group.appendChild(addBtn);
}

async function openSiklusPicker() {
  let siklusList;
  try {
    siklusList = await api.get('/siklus');
  } catch (e) {
    showAlert('Gagal memuat data siklus');
    return;
  }

  if (!siklusList || !siklusList.length) {
    showAlert('Belum ada siklus menu. Buat siklus terlebih dahulu di menu Ahli Gizi > Siklus Menu.');
    return;
  }

  document.getElementById('modal-title').textContent = 'Buat PO dari Siklus Menu';
  document.getElementById('modal-body').innerHTML = `
    <div class="mb-3">
      <label class="text-sm font-medium">Pilih Siklus</label>
      <div class="mt-1 space-y-1 max-h-48 overflow-y-auto border border-stone-200 rounded-lg p-2">
        ${siklusList.map(s => `
          <label class="flex items-center gap-2 cursor-pointer hover:bg-stone-50 p-1.5 rounded">
            <input type="checkbox" class="siklus-check" value="${s.id}">
            <span class="text-sm">${s.nama} — ${s.kategori_penerima || '-'} (${s.jumlah_porsi || 0} porsi)</span>
          </label>
        `).join('')}
      </div>
    </div>
    <div id="po-preview"></div>`;

  const saveBtn = document.getElementById('modal-save');
  saveBtn.textContent = 'Generate Draft';
  saveBtn.style.display = 'inline-block';
  saveBtn.onclick = generatePOFromSiklus;

  document.getElementById('modal').classList.remove('hidden');
  document.getElementById('modal').classList.add('flex');
}

async function generatePOFromSiklus() {
  const checked = document.querySelectorAll('.siklus-check:checked');
  const ids = Array.from(checked).map(cb => parseInt(cb.value));
  if (!ids.length) { showAlert('Pilih minimal satu siklus'); return; }

  const preview = document.getElementById('po-preview');
  preview.innerHTML = '<div class="text-center py-4 text-stone-500">⏳ Menghitung kebutuhan bahan...</div>';

  try {
    const result = await api.post('/purchase_order/generate-from-siklus', { siklus_ids: ids });

    if (!result.items || !result.items.length) {
      preview.innerHTML = '<div class="text-amber-700 bg-amber-50 p-3 rounded text-sm">Tidak ada bahan. Siklus dipilih belum memiliki menu.</div>';
      return;
    }

    preview.innerHTML = `
      <div class="border border-stone-200 rounded-lg overflow-hidden">
        <table class="w-full text-sm">
          <thead class="bg-stone-50">
            <tr>
              <th class="text-left px-3 py-2 text-xs font-semibold">Bahan</th>
              <th class="text-right px-3 py-2 text-xs font-semibold">Total</th>
              <th class="text-right px-3 py-2 text-xs font-semibold">+Buffer 10%</th>
              <th class="text-right px-3 py-2 text-xs font-semibold">Harga</th>
              <th class="text-right px-3 py-2 text-xs font-semibold">Subtotal</th>
            </tr>
          </thead>
          <tbody>
            ${result.items.map(i => `
              <tr class="border-t border-stone-100">
                <td class="px-3 py-2">${i.bahan_nama}</td>
                <td class="px-3 py-2 text-right mono">${i.total_qty} ${i.satuan}</td>
                <td class="px-3 py-2 text-right mono">${i.buffer_10} ${i.satuan}</td>
                <td class="px-3 py-2 text-right mono">${fmtIDR(i.harga_satuan)}</td>
                <td class="px-3 py-2 text-right mono">${fmtIDR(i.estimated_subtotal)}</td>
              </tr>
            `).join('')}
          </tbody>
          <tfoot class="bg-stone-50 border-t border-stone-200">
            <tr><td colspan="4" class="px-3 py-2 text-right font-semibold">Total Estimasi</td>
              <td class="px-3 py-2 text-right font-semibold mono">${fmtIDR(result.total_estimated)}</td></tr>
          </tfoot>
        </table>
      </div>
      <div class="mt-3 flex gap-2">
        <input id="po-supplier" placeholder="Nama Supplier" class="flex-1 h-10 px-3 border border-stone-200 rounded-md text-sm">
      </div>
      <button id="confirm-create-po" class="mt-2 bg-[#1e40af] hover:bg-[#1d4ed8] text-white px-4 py-2 rounded-md text-sm font-medium">Konfirmasi & Buat PO</button>`;

    document.getElementById('modal-save').style.display = 'none';
    document.getElementById('confirm-create-po').onclick = async () => {
      const supplier = document.getElementById('po-supplier').value;
      const tgl = new Date().toISOString().slice(0, 10);
      const nomor = 'PO-' + tgl.replace(/-/g, '') + '-' + Date.now().toString().slice(-4);
      const itemText = result.items.map(i =>
        `${i.bahan_nama}: kebutuhan ${i.total_qty} ${i.satuan} (buffer 10%: ${i.buffer_10} ${i.satuan}) @ ${fmtIDR(i.harga_satuan)} = ${fmtIDR(i.estimated_subtotal)}`
      ).join('\n');

      try {
        await api.post('/purchase_order', {
          no_po: nomor, tanggal: tgl, supplier_nama: supplier,
          item: itemText, total_nilai: result.total_estimated,
          status: 'Draft', catatan: 'Dibuat dari siklus: ' + result.siklus_refs.join(', '),
        });
        closeModal();
        renderPembelian();
        showToast('PO berhasil dibuat');
      } catch (e) {
        showAlert('Gagal membuat PO: ' + (e.message || 'Terjadi kesalahan'));
      }
    };
  } catch (e) {
    preview.innerHTML = `<div class="text-red-700 bg-red-50 p-3 rounded text-sm">Gagal: ${e.message || 'Terjadi kesalahan'}</div>`;
  }
}
